INSERT INTO `caozuorizhi` VALUES (5576, '管理员', 'xueyuanbumen', 'admin', '列表查询', '[XueyuanbumenView{} Xueyuanbumen{, id=21, xueyuanbumenUuidNumber=016, xueyuanbumenName=继续教育学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p>	西安理工大学继续教育学院全面负责学校成人高等学历教育、非学历教育、技能培训及相关行政管理工作，是经原机械工业部批准举办成人高等学历教育的正规机构，始办于1958年，是承担成人高等继续教育较早的院校之一。1980年学校恢复夜大学招生，1981年开始招收干部专修科，1986年举办函授教育，1988年经原机械电子部批准成立成人教育学院；2002年更名为继续教育学院。</p><p>	成人学历教育的办学形式有业余、函授教育两大类。办学层次有高中起点本科、专科起点本科等，我校成人高等继续教育共有46个专业，以机械、电气、水利水电、财会、管理、印刷等为鲜明特色。</p><p>	学校为适应在职人员继续学习的需要，以更新知识和提高技能为重点，积极推进“在线学习+线下面授”的混合式教学模式改革；按照人才市场的要求，建立多形式、多层次人才培训机制和模式，在学历教育基础上，积极开展高中及大学后的非学历继续教育和各种资格证书培训。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=20, xueyuanbumenUuidNumber=015, xueyuanbumenName=高科学院, xueyuanbumenAddress=泾河/长安校区, xueyuanbumenContent=<p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">西安理工大学高科学院是国家教育部批准的全日制普通本科院校，是学士学位授予权单位。学院现位于陕西省西安市西咸新区泾河新城，占地面积</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">540</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">亩，建筑面积近</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">20</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">万平方米，校园环境优美，设施设备齐全，实验实训条件在同类学校中领先。大型图书中心、体育场、教学楼、现代化的实验实训室集群、信息化公寓，结合现代科技新发展，产、学、研一体的现代化校园正引领学院向国际化大学标准迈进。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院传承西安理工大学优势专业和特色专业，开设了机械设计制造及其自动化、电气工程及其自动化、水利水电工程、土木工程、包装工程、电子信息工程、计算机科学与技术、工程管理、财务管理、英语、软件工程、智能制造工程等</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">11</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">个本科专业，面向全国招生，毕业生按国家规定颁发本科毕业证书和授予学士学位。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院秉承西安理工大学的教学理念和教学管理模式进行教育教学，对传统的培养模式进行了改革和创新，加大了实践环节，大幅度提高多媒体等现代化教学手段的使用，严格教育教学督导环节，有力地保障了教学质量。学院积极探索并努力实践复合型、应用型、创新型高素质的人才培养模式和“卓越工程师”人才培养方法，培养综合素质全面发展的具有很强的竞争能力和对岗位的适应能力的应用型高级人才，毕业生就业综合竞争力得到用人单位一致好评。每年参加全国硕士研究生入学考试上线人数达到在校生的13%</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">，达到参加考研人数的51%</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院秉承了西安理工大学多年的文化积淀，共享西安理工大学优质教学资源，一大批西安理工大学著名博士生导师、教授、博士担任各学科和专业的建设负责人，一线教学高级以上职称教师占</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">70%</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">以上。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院目前设有国家奖学金、国家励志奖学金、国家助学金、学校五项年度奖以及社会企事业单位在我校设立的“万信励志奖学金”、“理工晶科励志奖学金”等多种奖、助学金，为品学兼优和家庭困难的学生提供各种奖励、资助和勤工俭学岗位。学院现有</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">20</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">多个院级学生社团，学生活动丰富多彩，完整大学生活促进了学生全面发展。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院高度重视就业工作，与当地农业银行、苏州工业园区、长三角多个经济开发区的数十家企业签署校企就业合作单位，进行实习就业基地建设合作，为我院学生就业开辟了广阔的新途径，学院毕业生就业优势明显。</span></p><p><span class=\"ql-cursor\">﻿</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院以全面提高质量为核心，着力加强内涵建设，办学水平和社会声誉稳步提升。学院正在为实现建设以工为主、多学科协调发展、特色鲜明的大学的目标而努力奋斗，努力建设成为全国独立本科院校中具有示范性、推广性、辐射性的高校。</span></p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=19, xueyuanbumenUuidNumber=014, xueyuanbumenName=国际工学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p class=\"ql-align-justify\">西安理工大学国际工学院是2020年4月经教育部批准设立，由西安理工大学和澳大利亚詹姆斯库克大学共建的非独立法人中外合作办学机构，是我国中西部地区最早拥有本科、硕士、博士多层次招生培养的中外合作办学机构，目前在校本、硕、博学生共计1090人。</p><p class=\"ql-align-justify\">合作高校詹姆斯库克大学(James Cook University，简称JCU)是澳大利亚顶尖的国立研究型大学之一，是昆士兰州建校历史第二长的大学，也是英联邦高校协会(Association of Commonwealth Universities)的会员。JCU在机械学、土木工程、电子系统与物联网、电子电气工程、大数据科学等领域具有先进教育教学和科研水平。</p><p class=\"ql-align-justify\">国际工学院是西安理工大学13个本科学院之一，本科阶段开设机械设计制造及其自动化、土木工程、电子科学与技术、计算机科学与技术4个专业，每年计划招生280人，学制4年。硕士研究生开设有机械和土木水利两个专业。</p><p class=\"ql-align-justify\">学院师资队伍由詹姆斯库克大学外籍专家教师、西安理工大学具有丰富双语教学经验的名师以及全球招聘的一流国际化师资构成，其中詹姆斯库克大学选派的外籍教师不少于30%，其讲授的核心课程门数和学时数占全部课程门数和学时数的三分之一以上。中方主要任课教师均有留学、访学经历，有多位省级教学名师、省级一流课程负责人担任核心课程主讲教师。</p><p class=\"ql-align-justify\">西安理工大学国际工学院依托两校一流专业、强势学科以及优势教育资源，以“厚德、强基、创新、融合”为人才培养理念，通过专业交叉和学科融合，面向国家战略需求和产业发展趋势，围绕“智能制造”和“智能建造”培养方向，对接新一轮科技革命与产业变革，以推动“新工科”和“双一流”背景下学校教学改革和学科建设，培养面向智能制造和智能建造及可持续发展需要，适应未来科技进步，具有国际视野、创新精神、社会担当与职业道德的精英人才和社会栋梁。</p><p class=\"ql-align-justify\">学院创新实践成果丰硕。建院以来，学生参与各类科技创新实践活动共有1200余人次，获“挑战杯”等国家级奖项74项、省级奖项119项，获奖达976人次，获奖占比高达53.43%。“互联网+”大赛获奖144项，大学生创新创业训练计划项目立项57项； 在2025年的美国大学生数学建模大赛这一国际赛事中我院一位同学获得顶级奖项（O奖）一项，并获得H奖三项，同时2025年四支队伍在2025年陕西省“挑战杯”中再创佳绩，荣膺特等奖3项、一等奖1项，同样刷新并保持我校省赛最佳战绩。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=18, xueyuanbumenUuidNumber=013, xueyuanbumenName=电气工程学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p>		西安理工大学电气工程学院成立于	2019年	10月，以西安理工大学自动化学院原电气工程系和水利水电学院原电力工程系为基础组建。西安理工大学电气工程学院的前身可以追溯到	1958年北京机械学院自动控制系下设的工业企业电气化与自动化专业和	1960年陕西工业大学电机工程系下设的电厂电力网及电力系统、电机与电器专业。	1972年，北京机械学院和陕西工业大学合并组建陕西机械学院，形成了电力电子与电力传动和电力系统及其自动化两个主要分支发展方向。电力电子与电力传动方向是在原陕西机械学院自动控制系应用电子技术教研室基础上发展而来，后更名为西安理工大学自动化与信息工程学院电气工程系，主要教学科研方向为电力电子与电力传动。电力系统及其自动化方向是在原陕西机械学院水利工程系水电站动力设备教研室基础上发展而来，后发展为西安理工大学水利水电工程学院电力工程系，主要教学科研方向为电力系统及其自动化。	1998年，国家专业目录调整，两个专业统一调整为电气工程及其自动化专业，形成了一个专业由两个学院合办的格局。	2009年，电气工程及其自动化专业获批国家级特色专业称号。	2013年电气工程系新增电气类智能电网信息工程专业。	2023年学院新增储能科学与工程专业。电气工程学科的硕士生招生始于	1982年，	1984年获批电力电子与电力传动二级硕士学位授予权，	1993年电气工程学科取得电力电子与电力传动二级博士学位授予权，	1999年成为陕西省重点建设的优势学科，	2000年获批电气工程博士后流动站，	2003年获批电力系统及其自动化二级硕士学位授予权，	2011年获批电气工程一级硕士学位授予权，	2018年获批电气工程一级博士学位授予权。在全国第四轮学科水平评估中评为	C+，在第五轮学科评估中更进一步。</p><p>		历经	60余年的奋进努力，学院秉承学校优良的办学传统，践行“艰苦奋斗、自强不息”的办学精神。学院设有电力工程系、电力电子与电机系、电网信息与控制工程系、高电压与绝缘技术研究所、储能科学与工程研究所等	5个教学、科研系所和	1个电气工程实验中心，拥有专业实验室	26个，并建设有	1个校企共建国家级重点实验室，	1个校企共建国家地方联合工程实验室、	4个省级重点实验室和教学示范中心、	2个西安市重点实验室、	4个产学研基地。学院现有教职工	110人，其中教授	19人，副教授及高级工程师	28人，有国家及省部级高层次人才	5人，外籍客座教授	3名，外籍讲座教授与名誉教授	3名。目前全院在校学生	2000余人，其中本科生	1500余人，硕士、博士研究生近	500人。</p><p>		学院设有电气工程及其自动化、智能电网信息工程、储能科学与工程	3个本科专业。其中，电气工程及其自动化专业为国家级特色专业、首批国家级一流本科专业建设点。智能电网信息工程为国家首批开办的电气类本科专业。电气工程获国家卓越工程师教育培养计划	(本、硕、博）；电气工程核心课程教学团队为陕西省级教学团队。</p><p>		学院立足西北、面向全国开展电气工程领域的科学研究，特别在电力电子与特种电源装备、分布式发电与智慧能源、电力系统运行与控制、轨道交通电气控制等方面的研究取得了丰硕成果。学院教师主持纵向课题	320余项和企业委托课题	410余项，包括国家自然科学基金	48项、省部级基金	67项、国际合作项目	3项；近年来，科研课题到款	6200余万元，其中纵向课题经费	2151万元、企业委托课题经费合同额	4053万元；获得省部级及以上奖励	20项、厅局级及以上奖励	52项；发表高水平学术论文	1430余篇，其中	SCI检索	157篇、	EI检索	500余篇，在中科院一二区期刊发表论文	70余篇；出版电气工程领域中英文专著、教材	16本；授权国家发明专利	261件，其中	31项成果已得到转化。</p><p>		学院广泛开展国内外学术交流与合作，与德国、法国、日本、新加坡、美国、加拿大、澳大利亚等国的高校或科研机构签署了合作交流协定或开展学术交流，互派学者，建立了良好的合作关系。近	3年，派遣教师参加国际学术会议接近	200人次，资助学生参加国际学术会议近	30人次。各类社会团体及企业在学院设立各类奖助学金	10余项。</p><p>		学院秉持“育人为本、知行统一”的办学理念，继承传统，开拓创新，努力构建一流教学科研平台，培养理论基础扎实、创新能力强、综合素质高的电气工程领域“宽口径”、“复合型”一流工程技术人才。已为国家培养了六千余名高等专业技术人才，学院毕业生深受用人单位的好评。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=17, xueyuanbumenUuidNumber=012, xueyuanbumenName=马克思主义学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p class=\"ql-align-justify\">	西安理工大学马克思主义学院前身为北京机械学院马列教研部（1958年），2009年独立设置思想政治理论课教学科研部，2015年更名为马克思主义学院。学院为陕西省首批重点马克思主义学院、陕西省委教育工委重点扶持马克思主义学院。现设有习近平新时代中国特色社会主义思想概论教研室、马克思主义基本原理教研室、当代中国马克思主义教研室、中国近现代史纲要教研室、德育教研室、形势与政策教研室，有5个省级研究基地（中心）、1个省级人才培养模式创新实验区。</p><p class=\"ql-align-justify\">	<strong>师资队伍。</strong>现有全国优秀教师1人；教育部择优资助计划1人；全国高校思想政治理论课年度影响力提名人物3人；陕西省哲学社会科学和文化艺术领域领军人才1人；陕西省教书育人楷模1人、陕西省“巾帼标兵”1人；三秦人才津贴3人；陕西省思想政治理论课优秀教师1人；陕西高校人文社会科学青年英才支持计划1人；陕西高校青年杰出人才支持计划1人；陕西省决策咨询委员会委员1人。</p><p class=\"ql-align-justify\">	<strong>学科建设。</strong>学院2001年获批马克思主义理论与思想政治教育硕士学位授予权，2006年获批马克思主义理论一级学科硕士学位和思想政治教育二级学科博士学位授予权，2018年获批马克思主义理论一级学科博士学位授予权，2023年获批马克思主义理论学科博士后科研流动站。</p><p class=\"ql-align-justify\">	<strong>教育教学。</strong>学院承担全校本硕博学生的思想政治理论课教学工作。目前学院已建设有2门国家级一流本科课程、3门省级一流本科课程、3门省级“三进”精品课程、2门校级在线精品课程，获得省教学成果奖一、二等奖5项、省级教改重点攻关项目1项、省级思政课名师工作室1个、省级教学团队2个。在全国高校思想政治理论课教学展示活动中，共有1人获特等奖、2人获一等奖、3人次获二等奖；在陕西省思政课教师“大练兵”省级现场展示活动中，1人荣获特等奖、16人获“思政课程教学标兵”称号、6人获“思政课程教学能手”、2组师生团队获“思政课程教学团队教学能手”。</p><p class=\"ql-align-justify\">	<strong>科学研究。</strong>经过60余年的发展，学院形成了较为鲜明的研究特色和优势，围绕马克思主义基本原理与当代社会发展研究、新时代中国特色社会主义理论与实践研究、网络思想政治教育研究、中国共产党领导文化教育工作的历史进程和基本经验研究、高校思想政治理论课改革创新研究等5个学科方向展开研究。近年来，本学科共获批24项国家基金、90余项省部级课题，目前在研12项国家级项目、22项省部级科研项目，还有大量厅局级科研课题。在人民出版社、中国社会科学出版社、科学出版社等国家级出版社出版专著40余部。在《毛泽东邓小平理论研究》《思想理论教育导刊》《党的文献》《光明日报》《人民日报》等报刊发表论文800余篇。获陕西省哲学社会科学优秀成果一、二等奖7项，其他陕西省、西安市哲学社会科学优秀成果奖21项，厅局级奖项65项。</p><p class=\"ql-align-justify\">	<strong>人才培养。</strong>学院始终坚持立德树人宗旨，牢记为党育人为国育才使命，培养具有坚定马克思主义信仰，能够运用马克思主义立场、观点和方法，研究、分析与解决重大理论与现实问题的教学科研，及党政企事业单位高级研究与管理人才。</p><p class=\"ql-align-justify\">	<strong>学术交流。</strong>学院重视对外交流，先后成功举办了全国马克思主义理论博导论坛、“第二届信息化时代马克思主义理论创新与传播学术研讨会”等国际国内学术会议，与中国社科院、清华大学、美国波士顿大学、日本丽泽大学等国内外知名高校、科研院所开展广泛交流；思政课教学改革成效显著，实践育人成果获陕西省教学成果一、二等奖，教育部网站、中国教育电视台、《光明日报》《新华网》等多家媒体宣传报道，受到社会各界广泛关注。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=16, xueyuanbumenUuidNumber=011, xueyuanbumenName=艺术与设计学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p>西安理工大学艺术与设计学院成立于2005年。学院下设视觉传达、工业设计、环境设计、影像动画4个系和1个实验中心、1个公共艺术教育中心。本科招收视觉传达设计、工业设计、摄影、艺术与科技、动画、雕塑、产品设计7个专业。学院现有专业教师90人，其中教授6人，副教授30人。教师中具有博士学位27人，在读博士4人，具有硕士学位67人。2013年学院教学团队获批陕西省省级教学团队。</p><p>学院实验中心2017年获批省级实验教学示范中心，建有计算机教学中心、艺术展厅、建筑与环艺模型实验室、CMF木工加工实验室、快速成型实验室、数字摄影实验室、数字化图形处理实验室等专业实验室等。2014年学院获批陕西省省级人才培养创新示范区，学院是“中国工业设计技术服务联盟副理事长单位”、“陕西省社会科学普及基地”、 “陕西省动漫教育基地”、“教育部包装教学分指导委员会单位”，“陕西省高校摄影学会摄影专业委员会主任单位”、“中国文化管理协会理事单位”等。</p><p><strong>人才培养方面：</strong></p><p>学院现有在校本科生1200余人。现有工业设计二级博士授予权，工业设计二级硕士授予权，设计学一级硕士授予权，机械专业学位授予权，艺术设计（MFA）专业学位授予权，形成“一体两翼”的学科体系。2020年工业设计专业获批国家级“一流专业”建设点，产品设计专业获批陕西省“一流专业”建设点。学生在全国大学生艺术展演、全国大学生广告艺术设计大赛、平遥国际摄影节、全国三维数字化创新设计大赛、全国环艺学年奖及陕西省大学生“挑战杯”竞赛、陕西省大学生各类大赛中多次获得大奖。学生整体素质全面，动手能力强，具有较强的创意设计能力，受到了用人单位的欢迎与好评，近年来本科生就业率稳定在85%以上。</p><p><strong>学术研究方面：</strong></p><p>承担国家社会科学基金项目重点项目、一般项目、青年项目；某重点项目、国家艺术基金、教育部人文社科基金、文化部研究基金等纵向课题40余项。同时还承担了为经济建设服务的设计项目百余项。学院现为“陕西省动漫教育基地”、“大学生创新教育实践中心艺术设计基地”等。教师编写出版专著、教材近30部。学院获得陕西省2011年、2017年高等教育教学成果奖一等奖。教师国画作品曾获全国第十届美展铜奖；教师摄影作品曾获“索尼世界摄影奖”二等奖；教师和学生的设计作品相继获得2015、2017、 2018德国红点（Red Dot）概念设计奖。教师设计作品曾获第十八届中国科协年会创新创业大赛铜奖；教师指导的设计作品获得“互联网+”大赛全国铜奖、陕西省银奖等；指导的摄影作品获得教育部指导教师一等奖两项。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=15, xueyuanbumenUuidNumber=010, xueyuanbumenName=土木建筑工程学院, xueyuanbumenAddress=曲江/金花校区, xueyuanbumenContent=<p class=\"ql-align-justify\">土木建筑工程学院有着悠久的办学历史，办学根基可溯源到二十世纪30年代的西北联合大学土木系，并与50年代的西北工学院土木系、青岛工学院土木系和苏南工业专科学校建筑科有密切的渊源。在80余载的发展历程中，造就了一批优良的师资队伍，积累了丰富的办学经验，构建了高水平办学平台。</p><p class=\"ql-align-justify\">学院现有双聘院士2人，教职工153人。其中，教授31人，副教授46人，讲师58人；博士生导师33人，硕士生导师77人；全国优秀教师、全国优秀科技工作者、中科院百人计划、霍英东基金会高校青年教师奖、陕西省教学名师、陕西省百人计划等省部级以上人才28人次。在校本科生1151人，研究生838人，其中博士研究生144人，硕士研究生694人。</p><p class=\"ql-align-justify\">学院是首批“全国党建工作标杆院系”，设有院士工作室2个，拥有土木工程博士后流动站、土木工程一级学科博士学位授权点、土木水利博士专业学位授权点、力学一级学科硕士学位授权点、建筑学一级学科硕士学位授权点和工程管理（MEM）专业学位授权点；其中，土木工程一级博士学科覆盖结构工程、岩土工程、桥梁与隧道工程、市政工程、防灾减灾与防护工程、建设工程管理6个二级学科；力学一级硕士学科覆盖一般力学与力学基础、固体力学、流体力学和工程力学4个二级学科；建筑学硕士点覆盖建筑技术科学、建筑设计及其理论、城市设计及其理论3个学科方向。</p><p class=\"ql-align-justify\">学院拥有旱区水工程生态环境全国重点实验室、西部生态环境协同创新中心、陕西省黄土力学与工程重点实验室、陕西省智慧建造研究院、陕西高校新型智库生态水利与可持续发展研究中心、特殊岩土地下空间智能建造陕西省高校工程研究中心、人机共融智能机器人陕西省高校工程研究中心、陕西省研究生联合培养示范工作站，陕西省水利水电工程西安理工大学质量检测中心（水利部甲级资质）、西安理工大规划建筑设计研究院、西安理工大学水利水电土木建筑研究设计院，是陕西省岩土力学与工程学会理事长单位。</p><p class=\"ql-align-justify\">学院设有智能建造、土木工程、工程管理、工程力学、建筑学、城市地下空间工程、土木工程（国际班）7个本科专业。其中，土木工程专业是国家一流专业、陕西省特色专业，已三次通过住房和城乡建设部高等教育土木工程专业评估（认证）；工程管理专业是国家一流专业、陕西省特色专业，是陕西省第二所通过住房和城乡建设部高等教育工程管理专业评估（认证）的专业；城市地下空间工程专业是国家一流专业、教育部特设专业；工程力学专业是陕西省一流专业。学院建有陕西省土木工程实验教学示范中心、陕西省土木工程专业核心课程教学团队、陕西省工程管理专业人才培养模式创新实验区。有《结构力学》《土力学》《混凝土结构设计原理》《理论力学》4门国家级一流课程，有《结构力学》《土力学》《混凝土结构设计原理》《动力学建模与仿真》4门陕西省课程思政示范课程，有《工程测量学》《钢筋混凝土结构》《工程力学》《材料力学》等10门陕西省精品（资源共享）课程。</p><p class=\"ql-align-justify\">学院坚持教学、科研并重的办学方针，注重特色科研团队的形成和建设，努力构筑与学院发展相适应的高水平科研平台。学院科研工作紧密围绕国家经济建设，特别是服务于西部大开发、“一带一路”建设、智能建造与建筑工业化、黄河流域生态保护与高质量发展、西北乡村振兴，充分发挥科研优势，开展国家、省部级等各类纵向课题研究，并积极参与国家青藏铁路、南水北调、西气东输、三峡工程和西安地铁等国家和地区大、中型土木建筑和水利水电工程的科研、设计和生产任务。在全院教职员工的努力下，科研项目规模和层次不断发展，科研经费逐年递增。在1978年全国科学大会上，获得4项全国科学大会奖，1988年获国家科技进步奖3项，其中一等奖1项。近5年，学院获批国家级项目72项，新增科研项目800余项，科研到款2.1亿元；发表高水平学术论文900余篇，其中三大检索论文500余篇；出版专著/教材40余部，主、参编国家标准与行业规范14部；授权国家发明专利100余项；获陕西省科学技术一等奖等省部级科技奖励16项。近年来，主、承办国内高水平学术会议10余场；承担川藏铁路、引汉济渭、东庄水库、西安地铁及西部的机场、阳江抽蓄、渭河治理、幸福林带、秦岭保护等一批国家重大基础设施相关科研和生产任务，相关成果及应用情况受到中央电视台等媒体报道。学院积极开展国际合作与交流，与英国胡弗汉顿大学、爱尔兰利莫瑞克大学签署了本科联合培养协议，建立了良好的合作关系。并与澳大利亚詹姆斯库克大学合作，成立了国际工学院，招收土木工程本硕博学生。</p><p class=\"ql-align-justify\">学院长期坚持“育人为本、知行统一”的办学理念，重视基础理论教学和工程实践能力的培养，土木建筑领域的毕业生具备扎实的理论基础、较强的工程实践创新能力和优良的工作作风，学生就业渠道通畅，深受用人单位欢迎。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=14, xueyuanbumenUuidNumber=009, xueyuanbumenName=计算机科学与工程学院, xueyuanbumenAddress=曲江/金花校区, xueyuanbumenContent=<p>	计算机科学与工程学院起步于上世纪七十年代末，1994年成立计算机系，2002年7月成立学院。</p><p>	学院下设计算机科学与技术系、网络工程系、软件工程系和物联网工程系四个教学单位，设有计算机科学与技术、网络工程、软件工程、物联网工程及人工智能五个本科专业。其中，计算机科学与技术专业2010年入选陕西省特色专业，2013年入选教育部“卓越工程师人才培养计划”，并与软件工程专业先后获批国家级一流本科专业建设点，网络工程与物联网工程专业获批“陕西省一流专业”。计算机科学与技术、网络工程和软件工程三个专业通过中国工程教育认证。</p><p>	学院具有计算机科学与技术一级博士学位授予权，软件工程一级硕士学位授予权和电子信息领域专业硕士学位。学科覆盖学院全部本科专业，形成了本、硕、博完整的高级技术人才培养体系。近三年，计算机科学与技术学科软科排名位列全国前30%。2022年，计算机科学学科进入ESI全球排名前1%。</p><p>	学院教师队伍结构合理，师资力量雄厚。现有教职工140人，其中教授、副教授55人，博士生导师15人，硕士生导师49人。学院特聘院士2人、国家级人才2人，入选陕西省教学名师3人、陕西省“特支计划”科技创新领军人才1人，省级创新人才特聘教授7人，陕西省中青年科技创新领军人才3人，陕西青年科技奖1人，陕西省高校青年杰出人才1人，陕西省青年科技新星2人。目前在校本科生1400余人，硕、博研究生、留学生500余人。</p><p class=\"ql-align-justify\">	<span style=\"background-color: rgb(253, 253, 253);\">学院坚持立德树人，不断推进教育教学改革。建成</span>国家级一流本科课程2门，省级一流课程、精品资源共享课程、在线课程等10门，并在爱课程、智慧树等国家级慕课平台上线课程4门。学院获批省级实验教学示范中心1个，拥有一流的教学、科研、实验环境，建设有计算机组成原理与接口技术、嵌入式系统、网络工程、软件工程、物联网等实验室，实验设备功能齐备、性能先进。近年来，学院获省级、校级教学成果奖20余项，在全国“互联网+”竞赛、“挑战杯”竞赛、ACM/ICPC竞赛、信息安全技术技能大赛、全国研究生移动终端应用设计创新大赛、世界机器人大赛等各项学科竞赛中获国家奖30余项，省级奖100余项。</p><p class=\"ql-align-justify\">	学院坚持<span style=\"background-color: rgb(253, 253, 253);\">基础研究与应用研究并举，科研实力显著增强。依托学院建有</span>陕西省网络计算与安全技术重点实验室、西安市轨道交通智能技术重点实验室、智能感知与系统安全创新引智基地、人机共融智能机器人陕西省高校工程研究中心等6个省市级重点科研平台。近年来，学院紧跟国家数字经济发展战略，在智能计算、计算机视觉、图像处理、网络安全、物联网技术等多个领域合理布局，凝练方向，获批陕西省创新团队支持计划2项、陕西省高校青年创新团队2项。近年来，获批国家重点研发项目课题近10项，国家自然科学基金74项，省部级重点项目近20项，累计科研经费突破1亿元；获省部级以上科技奖励8项；授权发明专利200余项；发表高水平论文500余篇；出版专著及教材20余部。</p><p class=\"ql-align-justify\">	学院广泛开展国内外交流与合作，影响力不断提升。学院与澳大利亚詹姆斯库克大学开展本硕博全层次合作办学，与美国密苏里大学堪萨斯分校开展“3+1+1”研究生联合培养计划。先后与美国、日本、英国、澳大利亚、新加坡等国家的著名大学和学术机构开展合作研究及学术交流，建立了良好的合作关系。自2018年起，学院已招收本硕博留学生21名。</p><p class=\"ql-align-justify\">	学院毕业生专业基础知识扎实、创新实践能力强，综合素质高，深受用人单位好评，一次就业率达95%以上。毕业生大多数就业于沿海和经济发达地区，在华为、腾讯等知名IT企业、科研院所及政府部门发挥着重要的作用。</p><p class=\"ql-align-justify\">	长期以来，学院秉承“惟实、励新、笃信、至善”的院训，坚持立德树人根本任务，努力培养德智体美劳全面发展的社会主义建设者和接班人，为实现追赶超越目标和推进“双一流”建设而努力奋斗！</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=13, xueyuanbumenUuidNumber=008, xueyuanbumenName=人文与外国语学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p class=\"ql-align-justify\">		西安理工大学人文与外国语学院成立于2009年7月，其前身是1996年3月由原社会科学系和外语教学部合并组建成立的人文社会科学学院。学院拥有法学、英语、日语三个本科专业，英语专业入选国家级一流本科专业建设点。学院具有外国语言文学一级学科硕士点，翻译硕士（MTI）专业学位、法律硕士（JM）专业学位授权点，外国语言文学硕士一级学科获批国家高水平大学特色学科平台建设项目，法学专业与马克思主义学院联合招收法学方向学术型硕士研究生。学院为中国高等教育学会外语教育研究分会常务理事、中国法学教育研究会理事、中国日语教学研究会西北分会副会长、陕西省汉语国际教育研究会理事等多个学术机构成员单位。</p><p class=\"ql-align-justify\">		学院下设	4	系	2	部	3	所	2	中心	1	站：法律系、英语系、日语系、中文系、大学外语教学一部、大学外语教学二部、科技英语翻译研究所、语言学与文学研究所、法学研究所、综合实验中心和翻译硕士教育中心、省级普通话水平测试站。现有教职工	1	29	名，其中教师	11	4	名，教授	5	名、副教授	4	6	名、省级教学名师	1	名、省级师德标兵	1	名、省级课程思政教学标兵	1	名；兼职教授	6	名、外籍专家	3	名。具有博士学位的教师	22	人、在读博士	4	人。外语教学部荣获省级	“	巾帼标兵岗位	”	称号。学院	80%	的教师具有海外留学、访学经历。</p><p class=\"ql-align-center\">		<strong>办学理念</strong></p><p class=\"ql-align-justify\">		学院坚持	“	教学为中心、学科为重点、科研为依托、教师为主导、学生为主体	”	的办学理念，形成了以本科教学为主、兼具高质量研究生培养的办学格局。</p><p class=\"ql-align-center\">		<strong>教学成果</strong></p><p class=\"ql-align-justify\">		学院不断推进教育教学改革，注重课程思政育人，深化专业建设，探索新的教学模式，优化课程体系，加强教学团队建设，取得了显著成效。获教育部颁发的	“	国家级大学英语教学改革示范点	”	称号；建有《科技英语翻译》《大学英语》两个省级教学团队；建成《大学英语》《基础英语》	2	门省级精品课程，《中国传统文化》省级精品资源共享课程，《中西语言文化对比与翻译》省级精品视频公开课程，《科技英语》《英语语言学》《刑法学》	3	门校级精品课程；获省级教学成果一等奖	1	项、二等奖	2	项，校级教学成果特等奖	6	项、一等奖	5	项；承担国家级、省级重点教学改革项目	3	项。	“	面向国际视野的理工科大学生	‘	英语双能力	+	文化素养	’	人才培养模式创新实验区	”	被确定为省级人才培养模式创新实验区。</p><p class=\"ql-align-justify\">		学院注重青年教师培养，提升教师教学水平。鼓励青年教师积极参加国家级、省级讲课比赛，成果显著，位居在陕高校前列。先后荣获全国高校教师教学创新大赛二等奖、全国教学创新大赛	—	中国外语微课大赛全国总决赛一等奖、外研社	“	教学之星	”	大赛全国总决赛一等奖、	“	外教社杯	”	全国高校外语教学大赛二等奖、外研社	“	教学之星	”	大赛陕西省特等奖、	“	外教社杯	”	全国高校外语教学大赛陕西赛区分赛一等奖等	40	余项省级以上奖励。</p><p class=\"ql-align-center\">		<strong>科研成果</strong></p><p class=\"ql-align-justify\">		近五年，申报获批国家社科基金项目	3	项，教育部人文社科基金项目	5	项，陕西省社会科学基金、陕西省社科界重大理论与现实问题、陕西省社科联外语专项课题等研究项目	31	项，陕西省教育厅人文社会科学专项和西安市社会科学规划基金项目	21	项，校级项目	57	项。出版专著	∕	译著、教材	29	部。发表学术论文	140	余篇。获陕西省哲学社会科学成果奖二等奖	3	项，陕西高等学校人文社会科学研究优秀成果奖二等奖、三等奖	5	项，西安市哲学社会科学优秀成果奖	3	项，陕西高校大学外语研究会年会论文一等奖	1	项。</p><p class=\"ql-align-center\">		<strong>学术交流</strong></p><p class=\"ql-align-justify\">		学院十分重视高水平学术交流活动，先后举办和承办了	“	西部地区首届翻译理论及外语教学研讨会	”“	中国科技法学会年会	”“	第十一届全国典籍翻译学术研讨会	”	等高水平学	术	会议	；	设立了	“	外国语言文学博士讲坛	”“	人文论坛	”	，定期聘请国内外知名教授、学者来学院讲学。</p><p class=\"ql-align-center\">		<strong>国际合作</strong></p><p class=\"ql-align-justify\">		学院与美国东新墨西哥大学、美国密苏里大学堪萨斯分校、日本早稻田大学、日本福井大学、日本上智大学等国外知名大学建立了良好的交流与合作关系，为师生访学、课程学习、暑期实习搭建了平台。学院教师前往英国、美国、澳大利亚、瑞士、	日本等国家知名高校深造或进修	100	余	人次；学生参加海外实习或进修项目	50	余	人次。</p><p class=\"ql-align-center\">		<strong>教学设施</strong></p><p class=\"ql-align-justify\">		学院	拥	有良好的办学条件。建有同声传译室、云网络语言实验室、	CAT	机辅翻译实验室、智慧教室、研讨室、自主学习教室、外语在线测试平台、普通话机考实验室、模拟法庭、法律实务综合模拟平台等，为人才培养提供了良好的硬件环境。</p><p class=\"ql-align-center\">		<strong>人才培养</strong></p><p class=\"ql-align-justify\">		学院以	“	提升学生综合素质、全面服务学生成才	”	为目标，坚持	“	以本为本、德育为先、能力为重、注重成长	”	，形成了以	“	文曲星领航计划	”	为引领的	“	一系一精品	”	全员育人模式，不断提升	“	一节一会一月一讲坛	”	校内知名学生品牌活动。学院	多次	承办全国大学生英语竞赛，	“	外研社杯	”	全国英语演讲、阅读、写作、辩论赛，西北地区研究生英语演讲大赛等赛事，参与人数、获奖人数屡创新高，曾获全国优秀组织奖。学院定期举办	“	英语辩论大赛	”“	英语配音大赛	”“	英语戏剧大赛	”“	日语演讲大赛	”“	法律宣传月	”	等活动，为学生成长成才搭建良好发展平台。</p><p class=\"ql-align-justify\">		学院重视学生德智体	美劳	全面发展，注重学生创新能力的培养和综合素质的提高，将理想信念教育、爱国荣校教育、成长成才教育、诚信感恩教育、形势与政策教育、安全和心理健康教育与大学生思想政治教育、校园文化活动相结合，先后涌现出全国三好学生	，	陕西省三好学生、优秀学生党员	，	全国先进班集体等一批先进典型。</p><p class=\"ql-align-center\">		<strong>毕业生去向</strong></p><p class=\"ql-align-justify\">		学院不断深化教育教学改革，创新人才培养模式，培养和造就了一批专业基础扎实，综合素质全面的优秀人才。学院通过研究生推免、海外留学、优研项目为国内外知名学府输送优质生源，毕业生先后被宾夕法尼亚大学、波士顿大学、爱丁堡大学、北京大学、浙江大学、	中国人民大学、	香港中文大学、北京外国语大学、	中国政法大学、	日本大阪府立大学、日本筑波大学等名校录取，考研率稳定在	30%	左右。毕业生进入政府、司法机关、科研院所、企事业单位等领域，就业于司法仲裁、法律服务、外事、经贸、文化、新闻出版、教育、旅游等多种行业，就业率保持在	95%	左右。</p>, createTime=2025-11-07}, XueyuanbumenView{} Xueyuanbumen{, id=12, xueyuanbumenUuidNumber=007, xueyuanbumenName=理学院, xueyuanbumenAddress=曲江校区, xueyuanbumenContent=<p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">理学院坐落于风景秀丽的曲江新区，起源于1949年的基础部，经过几十年沐风栉雨，于1995年撤部建院成立理学院。学院始终坚持“厚基础、重交叉、强应用”的发展理念，加强与学校优势学科的交叉融合，形成了具有鲜明特色的西安理工大学数学、物理、化学等理学基础学科群。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院坚持以学科建设为龙头引领专业建设、平台建设、队伍建设等。现拥有1个一级博士学位授权点（数学）、1个二级博士学位授权点（物理电子学）、2个一级硕士学位授权点（物理、化学工程与技术），1个硕士专业学位授权点（材料与化工）。设有3个系（应用数学系、应用物理系、应用化学系）、2个重点实验室（陕西省超快光电技术与太赫兹科学重点实验室、西安市超快光电器技术重点实验室）、5个中心（陕西省数学与统计学实验教学示范中心、陕西省大学物理实验教学示范中心、陕西省化学实验教学示范中心、陕西省超快光电研究中心、西安理工大学应用数学中心）、3个基地（数学建模基地、化学化工与生物技术创新基地、超快光电技术研究中心陕西省国际科技合作基地）。开设6个本科专业（信息与计算科学、应用统计学、数据科学与大数据技术、应用物理学、应用化学、制药工程），其中“信息与计算科学”、“应用物理学” 、“应用化学”为国家级一流本科专业建设点。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院拥有一支爱岗敬业、治学严谨、乐于奉献的师资队伍。现有教职工164人，其中博导、硕导70人，教授、副教授71人，具有博士学位124人。现有国家级青年人才1人，全国优秀教师1人，省级教学名师3人，省级师德标兵2人，省级优秀工作者1人，省杰青、领军人才等省部级人才称号20余人次，省科技创新团队1个，省青年创新团队3个。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院积极推进“以本为本，四个回归”，坚持本科教学中心地位不动摇，稳步提升教育教学质量。“大学物理”为国家级一流课程，“线性代数” 、“电动力学” 、“理工创新工坊”为省级一流课程。“大学物理”、“工程化学”、“大学物理实验”、“高等数学”、“数学建模”为陕西省精品课程。“线性代数”、“电动力学”、“原子物理”为陕西省精品资源共享课程。“数学分析”、“概率论与数理统计”、“复变函数与积分变换”、“ 应用化学概论（双语）”为校级精品课程。建成省级教学团队4个，省级专业综合改革试点项目1个，省级人才培养创新实验区2个。学院获批国家教研项目5项，省级重点教研项目8项；获省级教学成果奖8项，发表教改论文100余篇，主编教材26部、参编教材18部。入选国家十二五规划教材1部，获陕西省优秀教材奖4项。获2022年“第二届全国高校教师教学创新大赛”一等奖1项，获陕西省高校教师教学创新大赛一等奖2项，二等奖1项，三等奖2项，优秀奖1项。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0); background-color: initial;\">学院一贯重视科学研究，坚持“以问题为驱动，以成果为导向”，加强应用成果落地，产出国内一流的高水平科研成果。近五年来，	共获批国家级科研项目41项，其中国家级重大重点项目4项；省部级科研项目70项，其中重大重点项目9项；厅局级科研项目45项。获得陕西省科学技术二等奖2项，陕西省青年科技奖1项，陕西省高等学校科学技术奖一等奖4项。获批陕西省重点实验室1个，建立了超快光电研究中心和应用数学中心。共发表高水平学术论文695篇，授权专利45项。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院紧抓学风建设和学生就业两个关键环节，形成了“夯实基础、朋辈互助、研学领航”的良好学风。现有在校生1200余人，其中本科生800余人，博士、硕士研究生400余人。为提高学生应用理科知识解决实际问题的实践能力和创新能力，积极组织学生参加各项科技文化活动，在国家和省级大学生“挑战杯”竞赛、数学建模大赛、互联网+创新创业大赛、大学生英语竞赛、大学生数学竞赛、全国大学生化工设计竞赛中，累计获国家、省级奖1200余项，连续十年获数学建模优秀组织奖，奖数位于全省前列。近几年，学院实现高质量就业，就业率达到百分之九十以上，其中考研升学率基本保持在40%左右。</span></p>, createTime=2025-11-07}]', '2025-11-07 19:34:23', '2025-11-07 19:34:23');
INSERT INTO `caozuorizhi` VALUES (5577, '管理员', 'dictionary', 'admin', '列表查询', '[DictionaryView{} Dictionary{, id=169, dicCode=dengji_types, dicName=项目等级, codeIndex=12, indexName=学校青年项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=168, dicCode=dengji_types, dicName=项目等级, codeIndex=11, indexName=学校专项项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=167, dicCode=dengji_types, dicName=项目等级, codeIndex=10, indexName=学校一般项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=166, dicCode=dengji_types, dicName=项目等级, codeIndex=9, indexName=学校重点项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=165, dicCode=dengji_types, dicName=项目等级, codeIndex=8, indexName=学校重大培育项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=164, dicCode=dengji_types, dicName=项目等级, codeIndex=7, indexName=小额横向项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=163, dicCode=dengji_types, dicName=项目等级, codeIndex=6, indexName=一般横向项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=162, dicCode=dengji_types, dicName=项目等级, codeIndex=5, indexName=重点横向项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=161, dicCode=dengji_types, dicName=项目等级, codeIndex=4, indexName=重大横向项目, superId=null, beizhu=, createTime=2025-11-07}, DictionaryView{} Dictionary{, id=160, dicCode=dengji_types, dicName=项目等级, codeIndex=3, indexName=市厅级项目, superId=null, beizhu=, createTime=2025-11-07}]', '2025-11-07 20:17:33', '2025-11-07 20:17:33');
