DROP TABLE IF EXISTS `fankui`;
CREATE TABLE `fankui`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键 ',
  `yonghu_id` int NULL DEFAULT NULL COMMENT '科研人员',
  `fankui_uuid_number` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '反馈编号',
  `fankui_name` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '反馈名称  Search111 ',
  `fankui_types` int NULL DEFAULT NULL COMMENT '反馈类型 Search111',
  `fankui_content` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '反馈内容 ',
  `insert_time` timestamp NULL DEFAULT NULL COMMENT '反馈时间',
  `create_time` timestamp NULL DEFAULT NULL COMMENT '创建时间  show1 show2 photoShow',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '反馈' ROW_FORMAT = Dynamic;

