INSERT INTO `xueyuanbumen` VALUES (6, '001', '材料科学与工程学院', '曲江/金花校区', '<p>  材料科学与工程学院是西安理工大学创建最早的院系之一，其名称历经北京机械学院机械二系、陕西机械学院机械一系、陕西机械学院金属材料工程系之后，于1996年确定为现名。学院创建以来，经过几代材料人的艰苦奋斗，在教学、科研、学科建设等方面取得长足的发展。</p><p>  学院坚持走教学与科研共同发展之路，下设材料科学与工程系、材料成型与控制系、材料物理与化学系、能源材料与器件系4个教学系和1个以本科实验教学为主的材料科学与工程实验中心，有材料科学与工程、材料成型及控制工程、材料物理、智能材料与结构、新能源材料与器件5个本科专业。具有材料科学与工程一级学科博士学位授予权，覆盖材料学、材料加工工程、材料物理与化学三个二级学科，并设有材料科学与工程博士后科研流动站。有15个依托本院建设的国家级和省部级重点科研基地、4个依托本院建设的西安市重点实验室、1个依托本院建设的“谢赫特曼诺奖新材料研究院”。近年来，先后承担科技部重大专项、国家重点研发计划、国家自然科学基金等研究课题，每年科研经费6000余万元。获各类科技奖60余项，其中国家级7项。</p><p>  学院有中国工程院外籍院士1人。专任教师130名，其中教授35人，副教授57人，博士学位130人，结构合理，力量雄厚。国家级人才5人，国家和陕西省突出贡献专家5人，教育部新世纪优秀人才3人，陕西省省级人才39人次。陕西省教学名师1人，陕西省师德标兵1名，陕西省师德楷模1人。陕西省高校黄大年式教学团队、陕西省顶尖人才和创新团队、陕西省三秦学者创新团队、陕西重点科技创新团队等陕西省省级教师、科研团队10个。</p><p>  现有材料科学与工程、材料成型及控制工程、材料物理3个专业通过工程教育专业认证并入选国家级一流专业建设点，2个国家级特色专业，1个卓越工程师教育培养计划专业，1个国家级“专业综合改革”试点专业，1门国家一流课程，3门省级一流课程，1门省级课程思政示范课，15项国家级及省部级教学成果奖。</p><p>  学院扎实落实立德树人根本任务，秉承“淬砺成材，料琢成器”院训，践行“传承，淬炼，家国情怀”育人理念，培养了一大批优秀的工程和技术管理人才。重视培养学生的创新意识、实践能力以及社会责任感，以丰富的校园文化、科技活动为载体，服务学生成长成才和全面发展。近五年，学生在大学生课外学术科技作品及各类竞赛获国家级奖70余项。其中，中国国际“互联网+”大学生创新创业大赛国赛金奖4项、银奖6项、铜奖11项；在金相技能大赛、材料热处理创新创业赛、铸造工艺大赛、失效分析大赛等全国性学科竞赛中获奖40余项。</p>', '2025-11-07 12:00:10');
INSERT INTO `xueyuanbumen` VALUES (7, '002', '机械与精密仪器工程学院', '曲江/金花校区', '<p>机械工程及自动化系（简称机自系）隶属机械与精密仪器工程学院，是在1958年原北京机械学院成立的机床、工具等专业基础上发展起来的具有悠久办学历史和光荣传统的教学科研单位。发展过程中与原陕西工业大学机械系融合，发展为原陕西机械学院的机床教研室、机械制造工艺教研室和机械电子教研室。1995年机械与精密仪器工程学院成立，机床教研室、机械制造工艺教研室和机械电子教研室合并组建为机械工程及自动化系。</p><p>机自系目前设有机械设计制造及其自动化（含卓工班）和工业工程专业，每年分别按照10个班和2个班招生。其中机械设计制造及其自动化专业2003年获批“陕西省名牌专业”，2008年获批“国家级特色专业”，2016年通过工程教育认证，2017年获批陕西省“一流专业”建设专业；2010年首批获得申办“卓越工程师班”办学资格，2018年“新工科背景下机械设计制造及其自动化专业改造升级路径探索与实践”获批教育部新工科建设项目。1999年，本系开办的工业工程专业是国内较早在工科学院设立该专业的院系之一。2017年该专业获批陕西省“一流专业”培育专业，推进机械工程背景下懂技术懂管理的复合型人才培养水平的提升。</p><p>机自系依托陕西省重点优势学科机械工程学科，分别于1993、1998、2000年获得“机械设计及理论”、“机械设计及自动化”、“机械电子工程”博士学位授予权，并于1999年设立机械工程博士后流动站。2000年获得“机械工程”一级学科博士授予权。2011年与“控制科学与工程”一级学科联合设立“工业装备制造与系统集成”交叉博士点学科。围绕数控装备设计方法与创新开发技术、制造技术与物流系统集成、数控装备性能测控技术、机电系统分析与测试技术、生产过程控制与状态检测技术等方面展开研究，在机床整机性能设计与分析、结合面基础研究与应用、精密小孔及超长深孔振动钻削理论及方法、现代测控理论与装备等方面形成了鲜明的科学研究特色。</p><p>机自系现有教师和实验专职人员62人，其中高级职称28人，博士生导师10人，硕士生导师28人，92%以上的教师具有博士学位，共同承担学院及校内相关专业50余门课程的教学工作；入选全国优秀教师、陕西省三五人才、三秦人才、省教学名师、省师德标兵、省优秀教师、省科技新星等16人次，建有陈学东院士工作室。本系依托“国家实验教学示范中心”、“教育部数控机床及机械制造装备集成重点实验室”、“陕西省机械制造装备重点实验室”、“陕西省高等学校实验教学示范中心”、“现代装备绿色制造2011协同创新中心”等基地平台以及10余个专业实验室，建立了完善的实践教学平台，实验室面积6500多平方米，仪器设备近5000台（套），设备总值6900余万元。其中，机械工程实验中心作为本系的专业实验室，每年承担30门左右的实验和综合实践课程的教学工作。</p><p>机自系始终坚持育人为本，全面推行以学生为中心的教育理念，积极开展教学改革和人才培养模式探索，现有“陕西省教学示范团队”1个，建成陕西省机械基础实验教学示范中心以及省级人才培养模式创新实验区各1个。本系历来重视学生创新创业能力培养，积极引导学生参加各类竞赛活动，近三年本专业学生先后获得“挑战杯”、全国大学生工程训练综合能力竞赛、机械设计创新大赛、卓越工程师教育联盟毕业设计大赛、数学建模、工业工程改善创意竞赛、大学生沙盘模拟经营创业大赛 、“互联网+”创新创业大赛等国家奖49项，省级奖160余项。</p><p>机自系紧跟学院、学校及国家人才培养战略，历经60余年的建设和发展，铸就了一支学术和教学水平过硬的师资队伍，为机械工程相关行业的企事业单位培养了近万名高级工程技术和管理人才。他们牢记“祖国、荣誉、责任”的校训，勤奋工作，涌现出大批杰出校友，为国家科技进步和社会发展做出了重要贡献。</p>', '2025-11-07 12:02:19');
INSERT INTO `xueyuanbumen` VALUES (8, '003', '自动化与信息工程学院', '曲江/金花校区', '<p><span style=\"color: rgb(96, 96, 96);\">自动化与信息工程学院创建于1958年，有着悠久的办学历史和艰苦创业的优良传统，现已发展成为我校集自动化、电子及信息类专业于一体，学生规模最大的学院之一。</span></p><p><span style=\"color: rgb(96, 96, 96);\">学院下设信息与控制工程系、电子工程系、通信工程系和三电教学实验中心四个教学单位，设有自动化（卓越）、电子信息工程、电气工程及智能控制、机器人工程、电子科学与技术、微电子科学与工程、集成电路设计与集成系统和通信工程8个本科专业。其中，自动化、电子科学与技术和通信工程入选“国家级一流本科专业”建设点；微电子科学与工程入选“省级一流本科专业”建设点。自动化专业入选教育部首批卓越工程师教育培养计划，2014年、2017年两次通过中国工程教育专业认证，电子科学与技术专业2019年通过中国工程教育专业认证，通信工程专业2023年通过中国工程教育专业认证。</span></p><p><strong style=\"color: rgb(96, 96, 96);\">学院教师队伍结构合理，师资力量雄厚。</strong><span style=\"color: rgb(96, 96, 96);\">现有教职工209人，其中博士生导师25人，教授33人，副教授45人，高级工程师7人。入选国家教学名师1人，讲座教授1人，全国优秀教师1人，国务院政府特殊津贴2人，陕西省有突出贡献专家1人，陕西省“重点领域顶尖人才”计划1人，陕西省“新世纪三五人才工程”1人，陕西省青年科技新星1人，陕西省教学名师8人，陕西省高等学校优秀教师1人，全国先进工作者1人，陕西省师德先进个人1人，西安市劳动模范1人，教育部高等学校专业教学指导委员会委员3人，省部级有突出贡献的专家、劳动模范、先进工作者、优秀教师、师德标兵等10余人。学院获批全国教育系统先进集体，入选三秦英才特殊支持计划3人、三秦英才引进计划3人。</span></p><p><strong style=\"color: rgb(96, 96, 96);\">学院坚持以学科建设为龙头，核心竞争力不断提升。</strong><span style=\"color: rgb(96, 96, 96);\">学院现有电子科学与技术和控制科学与工程2个一级学科博士后流动站，控制科学与工程和电子科学与技术2个一级博士学位授予权学科，电子信息和机械工程2个专业博士授予权学科，控制科学与工程、电子科学与技术和通信与信息系统3个一级硕士学位授予权学科，覆盖全部本科专业。现有2个陕西省重点学科，2个陕西省优势学科。最新一次的全国学科评估中，控制科学与工程学科进入全国前20%，电子科学与技术学科进入全国前40%。</span></p><p class=\"ql-align-justify\"><strong style=\"color: rgb(96, 96, 96);\">学院科研实力雄厚，成果丰硕。</strong><span style=\"color: rgb(96, 96, 96);\">学院坚持“四个面向”，倡导“以服务企业求支持，以贡献行业谋发展，以科技创新促成长”的发展理念，施行“需求导向与自由探索同推进、技术开发与基础研究相贯通”的发展路径，在自动化与电子信息领域积极开展有组织有重点的科学研究，科研实力雄厚。依托学院建有晶体生长设备与系统集成国家地方联合工程研究中心和陕西省复杂系统控制与智能信息处理重点实验室、新能源功率半导体器件及智能系统工程技术研究中心等12个省部级以及西安市无线光通信与网络研究重点实验室等3个厅局级科研平台。形成了大尺寸晶体生长控制理论、关键技术与系统集成，面向(重大)工程应用的智能检测技术与自动化系统，工业装备的故障诊断与健康管理，智能无人系统信息感知、协同优化与控制，信息感知与处理芯片技术与系统，宽禁带半导体材料制备，大功率半导体器件及功率集成，电磁理论及应用，无线光通信理论与技术，现代通信与智能目标检测理论及技术等特色优势研究方向，取得了丰硕的成果。研制的我国首台新一代电子级12英寸硅单晶生长成套技术装备已成功产业化，破解了大直径电子级硅单晶生长设备的“卡脖子”问题。近年来，学院先后获得省部级以上科技奖励32项，其中国家发明二等奖1项，省部级一等奖5项；承担纵横向科研项目2000余项，其中科技部重点项目（课题）、国家自然科学基金项目、军科委项目等国家级研究课题180余项；获国家发明专利授权1200余件；知识产权转让（许可）近400件；在国内外学术期刊发表论文2300余篇。近三年年均科研经费7000多万元。</span></p><p><strong style=\"color: rgb(96, 96, 96);\">学院坚持立德树人，大力推进教育教学改革。</strong><span style=\"color: rgb(96, 96, 96);\">学院拥有国家级教学团队1个，国家级精品课程2门，国家级精品资源共享课程2门，国家级一流本科课程4门，“国家级工程实践教育中心”1个，国家级实验教学示范中心1个，工信部校企协同育人示范基地1个，省级实验教学示范中心2个，省级教学团队1个，省级人才培养模式创新示范区3个。</span></p><p><span style=\"color: rgb(96, 96, 96);\">近年来，学院获国家级、省级和校级教学成果奖14项，获国家优秀教材建设二等奖1项，在科技竞赛方面，获“挑战杯”竞赛国家级金奖1项，国家级奖17项、省级奖24项，实现我校该赛事最高奖项零突破；在中国国际大学生创新大赛（原“互联网+”竞赛）中获国家级奖项40项，省级奖项95项；在全国大学生数学建模竞赛中获国家级奖项27项，省级奖项56项；在全国大学生等离子体竞赛中获得国家级奖项14项；在全国大学生节能减排社会实践与科技竞赛中获得国家级奖项8项；在大学生电子设计竞赛中获得国家级奖项11项，省级奖项73项；在研究生电子大赛中获国家级奖项45项，省级奖项223项。2024年，学院学生荣获国家级奖项70余项，省级以上奖项289项。学院学生在校园文化活动、社会实践及志愿者服务等工作成绩突出，学院团委多次荣获校级“五四红旗团委标兵”荣誉称号。</span></p><p><strong style=\"color: rgb(96, 96, 96);\">学院持续扩大对外交流合作，影响力不断提升。</strong><span style=\"color: rgb(96, 96, 96);\">先后与美、日、英、德等国近十所大学建立了良好的合作关系，与世界500强企业建立了西安理工大学-罗克韦尔自动化实验室、西安理工大学-艾默生数字化工厂和西安理工大学-飞思卡尔嵌入式应用实验室，与广州粤嵌通信科技股份有限公司共建“西理工-粤嵌众创空间”，与武汉凌特电子技术有限公司共建虚拟仿真实验室，加强学生的联合培养，夯实人才培养基础。目前，除校级奖学金外，企业、校友、知名人士先后在学院设立了“吴江经济技术开发区创新奖学金”“镇泰奖学金”“唐仲英奖学金”“罗克韦尔奖学金”“艾默生奖学金”等奖学金，覆盖了全部本科专业。</span></p><p><span style=\"color: rgb(96, 96, 96);\">由于学院学生基础理论扎实、专业知识面广、工程实践能力强、综合素质高，深受用人单位青睐。华为、中兴、华硕、特变电工、永济电机、许继集团、苏州汇川、维谛技术、创维集团、中芯国际、航天集团771所等国内外知名企业连续多年与学院优秀毕业生签约，近年来学院本科生就业率基本维持在90%以上</span></p><p>长期以来，学院始终发扬“艰难困苦，玉汝于成”的学院精神，秉承“行远自迩，立身笃信”的院训，形成“唯和，唯实，唯新，唯强”的学院作风，坚持“志于人师，精于育人”的学院教风和“学思结合，理实交融”的学风，不辱“育智能创新型人才，铸电子信息化伟业”的学院使命，努力培养德智体美劳全面发展的社会主义建设者和接班人，为实现追赶超越目标和推进“双一流”建设而努力奋斗！</p>', '2025-11-07 12:03:15');
INSERT INTO `xueyuanbumen` VALUES (9, '004', '水利水电学院', '曲江校区', '<p class=\"ql-align-justify\">	西安理工大学水利水电学院是我国西北地区水利水电教育教学和科学研究的重要基地。学院历经变迁，七易校名，办学历史源于1937年的西北工学院水利系，先后经历了西安动力学院、西安交通大学、陕西工业大学、西北农学院、陕西机械学院，1994年更名为西安理工大学水利水电学院。</p><p class=\"ql-align-justify\">	学院是全国首批博士学位授予单位，现有水利工程、环境科学与工程、农业工程3个博士一级学科以及动力工程及工程热物理、水土保持与荒漠化防治2个硕士学科，其中水利工程为国家一级重点学科、陕西省“双一流”建设学科，拥有土木水利、能源动力2个工程博士专业学位授权点和土木水利、能源动力、资源与环境3个工程硕士专业学位授权类别，并设有水利工程、农业工程博士后流动站。学院2010年获批水利工程专业学位教育综合改革试点单位，是全国64个试点高校之一，2014年获批全国示范性工程专业学位研究生联合培养基地，是全国28所高校之一。水利工程目前是西北地区水利类人才培养最多、重大工程参与最广、学术影响力最大的学科。</p><p class=\"ql-align-justify\">	学院现有教职工218人，其中教授59人，二级教授20人，三级教授18人；长江学者、国家杰青等国家级人才15人；中国青年女科学家、国务院政府特殊津贴等省部级荣誉称号者20余人；水利水电工程教师团队获批全国高校黄大年式教师团队，旱区生态水利教师团队获批陕西省高校黄大年式教师团队。</p><p class=\"ql-align-justify\">	学院设有水利水电工程、水<span style=\"color: black;\">文与水资源工程、能源与动力工程、新能源科学与工程、给排水科学与工程、环境工程、农业水利工程7个本科专业，其中水利水电工程、能源与动力工程、环境工程、水文与水资源工程、农业水利工程、给排水科学与工程6个专业为国家一流专业建设点，水利水电工程、能源与动力工程2个专业为国家级特色专业；水文与水资源工程、水利水电工程、环境科学与工程、农业水利工程、给排水科学与工程5个专业通过国家工程教育专业认证（住建部专业评估）。目前全院在校学生3500余人，其中博、硕士研究生1700余人。</span></p><p class=\"ql-align-justify\">	<span style=\"color: black;\">依托学院学科优势，建有旱区水工程生态环境全国重点实验室、水利水电国家级实验教学示范中心、省部共建西部生态环境协同创新中心、西北旱区生态水利学科创新（111）引智基地4个国家级科研、教学平台；建立省级智慧水利与智能建造产业学院，以及教育部西北水资源与环境生态重点实验室、旱区生态水文与灾害防治国家林业和草原局重点实验室、陕西省水力机械及其控制工程技术研究中心、陕西省水利水电虚拟仿真实验教学中心等15个省部级科研、教学平台。</span></p><p class=\"ql-align-justify\">	<span style=\"color: black;\">学院立足西北、面向全国开展水利水电科学研究，在</span>黄土高原综合治理、黄河流域生态保护与高质量发展、大西线调水、乡村振兴与海绵城市建设、水风光储多能互补、重大水电装备、特色坝工技术、沥青混凝土防渗技术等国家战略和系列重大工程技术研究中取得了丰硕成果。已构建黄土高原沟壑整治工程技术体系与水沙资源化利用模式，指导淤地坝建设5600余座；破解了沥青混凝土心墙高坝建设中的“卡脖子”问题，应用于全国80%以上沥青心墙坝工程并辐射到国外，引领世界沥青混凝土防渗技术的发展；研发出系列综合性能国际领先的水轮机，打破了大型水轮机技术的国际垄断，实现了水力设计技术从跟跑到领跑的跨越；提出了国际领先的多能互补协调运行技术，成功应用于世界最大的龙羊峡水光互补工程；创新了城市低影响开发理论与技术，支撑黄土地区海绵城市建设，助力西咸新区获批全球生态水文示范点；主编了我国水利信息平台行业标准，研发出国内首个水利综合集成平台，破解了水利软件国产化替代的瓶颈。</p><p class=\"ql-align-justify\">	近5年，承担科研项目1900余项，主持国家重点研发计划项目2项，国家重点研发计划课题7项，国家自然科学基金项目141项（其中重大、重点项目10项、国家杰出青年基金1项、国家优秀青年基金5项），科研到款6.5亿元，获国家科技进步二等奖2项，省部级奖50项，其中一等奖19项。</p><p class=\"ql-align-justify\">	学院积极推进国际化办学，专门设立水利学科研究生国际联合培养项目，选派优秀学生赴境外访学、联合培养。与美国亚利桑那大学、英国布鲁内尔大学、澳大利亚詹姆斯库克大学等20余所国际知名高校建立深度合作，形成了“3+1”、“2+2”、“3+1+1”等多种模式的国际合作办学项目。发起成立了生态水利与新能源国际联盟、“一带一路”国际水联盟等学术组织，与乌兹别克斯坦塔什干灌溉与农业机械化工程大学共建中-乌旱区水利协同创新联合实验室，深化“一带一路”教育科技合作。</p><p class=\"ql-align-justify\">	学院坚持以人才培养为中心、学科建设为龙头、科学研究为支撑；秉承优良传统，依托<span style=\"color: black;\">优势资源，构筑高水平办学平台；提出并践行“知识、能力、精神、素质”协调发展的人才培养模式，培养基础扎实、实践创新能力强、综合素质高的一流水利人才。培养的毕业生踏实肯干，工作能力突出，深受用人单位欢迎，“下得去，吃得苦，留得住，顶得上”是用人单位对我院毕业生的真实评价。</span></p>', '2025-11-07 12:20:31');
INSERT INTO `xueyuanbumen` VALUES (10, '005', '印刷包装与数字媒体学院', '曲江校区', '<p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">高举文明传承旗帜，赓续印刷工业薪火。1974年，为改变我国当时印刷工业落后面貌，培养高素质印刷技术装备人才，陕西机械学院（现为西安理工大学）创建了我国第一个“印刷机械”专业。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">作为全国最早成立并开展印刷包装类本科高等教育的院系之一，西安理工大学印刷包装与数字媒体学院历经50余年发展建设，已成为为我国印刷包装和文化传播行业培养高素质应用型人才的教育科研高地，也是推动我国印刷包装类高等教育走向国际化的重要先行者和积极践行者。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">学院现为中国印刷及设备器材工业协会、中国印刷技术协会常务理事单位，教育部轻工类专业教学指导委员会委员单位。设有</span><a href=\"https://printech-ybxy.xaut.edu.cn/index.htm\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(30, 80, 162); background-color: transparent;\">	印刷工程</a>	<span style=\"color: rgb(0, 0, 0);\">、</span><a href=\"https://bz-ybxy.xaut.edu.cn/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(30, 80, 162); background-color: transparent;\">	包装工程</a>	<span style=\"color: rgb(0, 0, 0);\">、</span><a href=\"https://xxkx-ybxy.xaut.edu.cn/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(30, 80, 162); background-color: transparent;\">	数字媒体技术</a>	<span style=\"color: rgb(0, 0, 0);\">三个本科专业，有印刷包装技术与设备二级博士学位授予权，轻工技术与工程、信号与信息处理、机械工程3个学术硕士学位授予权和材料与化工、电子信息2个专业硕士学位授予权。形成了本、硕、博完整的多层次人才培养体系。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">学院现有教职工123人，专任教师96人，其中教授15人、副教授32人，80%以上的专任教师具有博士学位和海外学习经历。学院教师入选国家级人才工程1人、教育部“新世纪优秀人才支持计划”1人、科技部中青年科技创新领军人才1人、陕西省特支计划青年拔尖人才1人及“省教学名师”2人，累计16位教师、校友获行业最高奖“毕昇奖”。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">学院教学建设成绩斐然，获国家教学成果二等奖1项，建设有4门国家级一流本科课程。印刷工程专业2005年被陕西省授予“名牌专业”称号、2008年获批为“省级特色专业”、2017年获批为“陕西省一流专业”建设项目、2019年获批为国家级“一流本科专业”建设点,2023年通过工程认证。包装工程专业2020年获批为国家级“一流本科专业”建设点。印刷工程专业软科排名连续5年蝉联“A+”，数字媒体技术专业软科排名“A”，包装工程专业软科排名“B+”。学院实验中心获评陕西省实验教学示范中心。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">近年来，学院科研工作实现较快增长，获国家自然科学基金面上项目、国家重点研发计划等省部级以上科研项目100余项，荣获陕西省科技进步奖、包装行业科学技术奖等省部级及行业协会奖50余项，获批发明专利300余项，发表高水平论文1300余篇，1个科研团队获批省级重点创新团队，并建有陕西省印刷包装工程重点实验室、陕西省印刷包装工程技术研究中心、陕西省绿色智能印刷包装协同创新中心3个省级科研平台和西安市机器视觉与印刷包装智能装备技术重点实验室。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">从1985年开始，学院与德国斯图加特媒介大学开展合作，1999年启动中德双学历教育项目，为中德两国印刷包装工业界培养技术和管理方面的国际化专业人才。该项目已建立4个国际教育实践基地，被德国校长联合会评为七个最佳中德教育合作项目之一，并通过德国教学委员会评估，德国驻华大使馆大使两次就该项目来校调研并给予高度认可。近年学院又陆续和挪威科技大学、日本千叶大学开展国际合作。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0);\">历经50年发展，学院培养了以中国印刷技术协会常务副理事长褚庭亮，国家科技进步二等奖获得者、北京印刷学院原副校长许文才，中国印钞造币集团有限公司首席专家、“全国五一劳动奖章”获得者、“大国工匠年度人物”提名人选马立项，中国航天科技集团五院研究员、北斗三号全球卫星导航系统北斗卫星副总设计师刘天雄，中国文化产业发展集团副总经理常晓霞，外贸无锡印刷股份有限公司总经理周明香，苏州苏大维格科技集团股份有限公司总裁朱志坚，国家杰出青年基金获得者、清华大学自动化系副主任鲁继文等为代表的一大批杰出校友、领军人才和近万名毕业生，为改革开放后国家印刷包装行业的发展腾飞与文化产业的繁荣兴盛贡献了源源不断的发展力量，做出了不可磨灭的历史贡献。</span></p>', '2025-11-07 12:21:48');
INSERT INTO `xueyuanbumen` VALUES (11, '006', '经济与管理学院', '曲江校区', '<p>	西安理工大学经济与管理学院创建于1919年，其前身为北平市商业补习学校，是我国高等工科院校最早设置管理学科的院校之一。经过多年的努力，学院在教学、科研、学科建设、师资队伍建设等方面都有了长足发展，形成了“同心、图强、务实、求新”的良好院风。</p><p>	目前学院设有工商管理、市场营销、人力资源管理、会计学、工业工程、金融学、信息管理与信息系统、经济学、大数据管理与应用、跨境电子商务等10个本科招生专业。工商管理专业为国家级一流本科专业建设点、国家级特色专业，会计学和工业工程专业是国家级一流本科专业建设点。学院设有大数据与智慧商业实践微专业，以满足复合型人才培养以及学生个性化、多样化发展需求，增强学生的就业竞争力。全院共有教职工170余人，其中专职教师144人，含博士生导师15人，教授25人，副教授38人，具有博士学位教师126人，形成了结构合理、梯队健全的科研教学队伍。有陕西省教学名师2名，陕西省创新人才推进计划(中青年科技创新领军人才)1人，三秦英才特殊支持计划(哲学社会科学和文化艺术领域领军人才2人，青年拔尖人才1人)，陕西省人文英才计划1人，陕西省师德先进个人2人，陕西省教育系统优秀教育工作者1人，陕西省青年科技新星2人，全省高校“青年杰出人才支持计划”3人。目前在校学生3300余名，其中含博士、各类硕士研究生（含MBA、EMBA、MPACC）等各类研究生1800余名。</p><p>	学院学科布局合理，体系完善，现有管理科学与工程、工商管理学两个博士学位授权一级学科和应用经济学硕士学位授权一级学科，建有管理科学与工程博士后流动站1个。管理科学与工程、工商管理学为校优势学科，是学校十三五规划重点扶持学科，亦为陕西省重点建设学科和优势学科。工商管理学下设企业管理、技术经济及管理、会计学二级学科授权点。在2017年教育部学位中心第四轮学科评估中，管理科学与工程一级学科被评为B+（前20%）；工商管理一级学科被评为B-（前40%），在2018年“软科中国最好学科排名”中，工商管理一级学科位列第50位（前25%），学科实力雄厚。</p><p>	学院是全国前56所第三批MBA和第二批EMBA教育授权院校，1996年开始招收陕西MBA学员，1997年和2009年分别开始招收全国MBA和EMBA学员，同时拥有会计硕士、金融硕士、工程管理硕士等专业学位授予权。学院是陕西省首批三项人才工程设岗单位，建有陕西高校哲学社会科学重点研究基地“城市经济与管理研究中心”，原陕西省省长程安东担任所长的“陕西城市战略研究院”设在我院。2018年杨善林院士在我院设立院士工作室。</p><p>	学院科研实力雄厚，承担各类国家级项目120项，其中国家自然科学基金61项，国家社会科学基金重点项目1项，一般项目47项，国家软科学2项，国家科技部基金8项；承担教育部基金50项，中国博士后基金15项，各类省部级项目510余项。学院年均科研经费1000余万元，科研成果获省部级奖70项，出版教材、专著90余部，发表学术论文1450余篇，其中SSCI、SCI、EI、ISTP、CPCI收录500余篇，高水平论文（含CSSCI、CSCD)820余篇。</p><p>	近年来，学院在教学质量工程建设及实践教学改革方面，取得一系列标志性成果。获国家级教学成果奖1项，省级教学成果奖9项，省级教改项目4项，获批国家级本科线上线下混合式一流课程1门，省级本科线下一流课程1门，线上课程1门，省级课程思政示范课程1门，省级精品课程7门，省级创新创业精品视频课程1门。获批大数据分析与智能决策陕西省高等学校重点实验室1个，省级人才培养模式创新实验区建设项目1项，省级“专业综合改革试点”项目1项，省级教学团队1个，省级虚拟仿真实验教学研究项目1项，省级新文科研究与实践项目1项，工信部“十四五”规划教材1部。</p><p>	经济与管理学院实验中心成立于1986年，2013年获批“省级实验教学示范中心”。实验中心现有面积1250平方米，设有企业管理模拟实验室、大数据分析实验室、会计与金融实验室、信息工程实验室、网络工程实验室、工业工程实验室、ERP实验室、企业管理虚拟仿真实验室、大数据与智能决策实验室等9个专业实验室，可满足学院各类学生的实验教学需要。配备450台高性能计算机及其它相关专用实验设备，资产总价值约1600万元，各类仪器设备1250台套，在培养学生创新创业方面发挥了重要作用。</p><p>	学院注重实践教学环节和学生创新能力的培养，对竞赛实行精细化管理，积极组织学生参加科技论坛、学术报告会、课外阅读、科技竞赛和成果展示、社会实践等形式多样的第二课堂活动。近年来，在校学生多次在全国大学生“挑战杯”课外学术科技作品竞赛和创业计划大赛、全国大学生英语竞赛、全国大学生沙盘模拟经营大赛、全国大学生市场调查与分析大赛、全国大学生市场研究与商业策划大赛、“能源杯”全国大学生财会技能挑战赛和陕西省工业工程改善创意大赛等各类比赛中获奖。学院创业团队获得2018年第四届中国“互联网+”大学生创新创业大赛国家铜奖、陕西省决赛季军（金奖），实现历史性突破。连续三年参加在韩国大邱举办的全球创新创业大赛（GIF，Global Innovator Festa），获得IDEA-THON行政安全部长奖（创意组最高奖）。</p><p>	学院与美的集团、陕西秦川机床、宁夏共享铸钢国家协同创新中心、美林数据科技股份公司、希格玛会计师事务所、吴江经济技术开发区、博众精工科技股份有限公司、西电集团、江苏京东信息技术有限公司、陕汽集团等企业在学生实习实训、产学研合作方面建立了长期合作关系；同时，与美国圣克劳德州立大学、美国西弗吉尼亚大学、华盛顿大学、伦敦布鲁内尔大学、日本福井大学、德国斯图加特媒介大学、比利时列日大学列日高商等多所海外知名大学建立了良好的院校合作交流关系。目前，“信息管理与信息系统”和“工业工程”本科专业与美国圣克劳德州立大学“信息安全”和“工程管理”硕士专业设有“3+2”合作项目；9个本科专业与比利时列日大学HEC列日高商设有“2+1+1+1”合作项目。</p><p>	学院有学校各项奖学金，并设有瑾瑜奖学金、东熙创新奖学金、蔚蓝奖学金、镇泰奖学金、创鑫奖学金、龙腾创新奖学金和吴江奖学金等企业奖学金。学院学风浓郁，文体、科技竞赛活动丰富多彩，校体育运动会获得“十连冠”，毕业生就业率高，就业质量好，学生工作多次被评为校学生工作先进集体。</p>', '2025-11-07 12:22:32');
INSERT INTO `xueyuanbumen` VALUES (12, '007', '理学院', '曲江校区', '<p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">理学院坐落于风景秀丽的曲江新区，起源于1949年的基础部，经过几十年沐风栉雨，于1995年撤部建院成立理学院。学院始终坚持“厚基础、重交叉、强应用”的发展理念，加强与学校优势学科的交叉融合，形成了具有鲜明特色的西安理工大学数学、物理、化学等理学基础学科群。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院坚持以学科建设为龙头引领专业建设、平台建设、队伍建设等。现拥有1个一级博士学位授权点（数学）、1个二级博士学位授权点（物理电子学）、2个一级硕士学位授权点（物理、化学工程与技术），1个硕士专业学位授权点（材料与化工）。设有3个系（应用数学系、应用物理系、应用化学系）、2个重点实验室（陕西省超快光电技术与太赫兹科学重点实验室、西安市超快光电器技术重点实验室）、5个中心（陕西省数学与统计学实验教学示范中心、陕西省大学物理实验教学示范中心、陕西省化学实验教学示范中心、陕西省超快光电研究中心、西安理工大学应用数学中心）、3个基地（数学建模基地、化学化工与生物技术创新基地、超快光电技术研究中心陕西省国际科技合作基地）。开设6个本科专业（信息与计算科学、应用统计学、数据科学与大数据技术、应用物理学、应用化学、制药工程），其中“信息与计算科学”、“应用物理学” 、“应用化学”为国家级一流本科专业建设点。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院拥有一支爱岗敬业、治学严谨、乐于奉献的师资队伍。现有教职工164人，其中博导、硕导70人，教授、副教授71人，具有博士学位124人。现有国家级青年人才1人，全国优秀教师1人，省级教学名师3人，省级师德标兵2人，省级优秀工作者1人，省杰青、领军人才等省部级人才称号20余人次，省科技创新团队1个，省青年创新团队3个。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院积极推进“以本为本，四个回归”，坚持本科教学中心地位不动摇，稳步提升教育教学质量。“大学物理”为国家级一流课程，“线性代数” 、“电动力学” 、“理工创新工坊”为省级一流课程。“大学物理”、“工程化学”、“大学物理实验”、“高等数学”、“数学建模”为陕西省精品课程。“线性代数”、“电动力学”、“原子物理”为陕西省精品资源共享课程。“数学分析”、“概率论与数理统计”、“复变函数与积分变换”、“ 应用化学概论（双语）”为校级精品课程。建成省级教学团队4个，省级专业综合改革试点项目1个，省级人才培养创新实验区2个。学院获批国家教研项目5项，省级重点教研项目8项；获省级教学成果奖8项，发表教改论文100余篇，主编教材26部、参编教材18部。入选国家十二五规划教材1部，获陕西省优秀教材奖4项。获2022年“第二届全国高校教师教学创新大赛”一等奖1项，获陕西省高校教师教学创新大赛一等奖2项，二等奖1项，三等奖2项，优秀奖1项。</span></p><p class=\"ql-align-justify\">		<span style=\"color: rgb(0, 0, 0); background-color: initial;\">学院一贯重视科学研究，坚持“以问题为驱动，以成果为导向”，加强应用成果落地，产出国内一流的高水平科研成果。近五年来，	共获批国家级科研项目41项，其中国家级重大重点项目4项；省部级科研项目70项，其中重大重点项目9项；厅局级科研项目45项。获得陕西省科学技术二等奖2项，陕西省青年科技奖1项，陕西省高等学校科学技术奖一等奖4项。获批陕西省重点实验室1个，建立了超快光电研究中心和应用数学中心。共发表高水平学术论文695篇，授权专利45项。</span></p><p class=\"ql-align-justify\">		<span style=\"background-color: initial; color: rgb(0, 0, 0);\">学院紧抓学风建设和学生就业两个关键环节，形成了“夯实基础、朋辈互助、研学领航”的良好学风。现有在校生1200余人，其中本科生800余人，博士、硕士研究生400余人。为提高学生应用理科知识解决实际问题的实践能力和创新能力，积极组织学生参加各项科技文化活动，在国家和省级大学生“挑战杯”竞赛、数学建模大赛、互联网+创新创业大赛、大学生英语竞赛、大学生数学竞赛、全国大学生化工设计竞赛中，累计获国家、省级奖1200余项，连续十年获数学建模优秀组织奖，奖数位于全省前列。近几年，学院实现高质量就业，就业率达到百分之九十以上，其中考研升学率基本保持在40%左右。</span></p>', '2025-11-07 12:24:24');
INSERT INTO `xueyuanbumen` VALUES (13, '008', '人文与外国语学院', '曲江校区', '<p class=\"ql-align-justify\">		西安理工大学人文与外国语学院成立于2009年7月，其前身是1996年3月由原社会科学系和外语教学部合并组建成立的人文社会科学学院。学院拥有法学、英语、日语三个本科专业，英语专业入选国家级一流本科专业建设点。学院具有外国语言文学一级学科硕士点，翻译硕士（MTI）专业学位、法律硕士（JM）专业学位授权点，外国语言文学硕士一级学科获批国家高水平大学特色学科平台建设项目，法学专业与马克思主义学院联合招收法学方向学术型硕士研究生。学院为中国高等教育学会外语教育研究分会常务理事、中国法学教育研究会理事、中国日语教学研究会西北分会副会长、陕西省汉语国际教育研究会理事等多个学术机构成员单位。</p><p class=\"ql-align-justify\">		学院下设	4	系	2	部	3	所	2	中心	1	站：法律系、英语系、日语系、中文系、大学外语教学一部、大学外语教学二部、科技英语翻译研究所、语言学与文学研究所、法学研究所、综合实验中心和翻译硕士教育中心、省级普通话水平测试站。现有教职工	1	29	名，其中教师	11	4	名，教授	5	名、副教授	4	6	名、省级教学名师	1	名、省级师德标兵	1	名、省级课程思政教学标兵	1	名；兼职教授	6	名、外籍专家	3	名。具有博士学位的教师	22	人、在读博士	4	人。外语教学部荣获省级	“	巾帼标兵岗位	”	称号。学院	80%	的教师具有海外留学、访学经历。</p><p class=\"ql-align-center\">		<strong>办学理念</strong></p><p class=\"ql-align-justify\">		学院坚持	“	教学为中心、学科为重点、科研为依托、教师为主导、学生为主体	”	的办学理念，形成了以本科教学为主、兼具高质量研究生培养的办学格局。</p><p class=\"ql-align-center\">		<strong>教学成果</strong></p><p class=\"ql-align-justify\">		学院不断推进教育教学改革，注重课程思政育人，深化专业建设，探索新的教学模式，优化课程体系，加强教学团队建设，取得了显著成效。获教育部颁发的	“	国家级大学英语教学改革示范点	”	称号；建有《科技英语翻译》《大学英语》两个省级教学团队；建成《大学英语》《基础英语》	2	门省级精品课程，《中国传统文化》省级精品资源共享课程，《中西语言文化对比与翻译》省级精品视频公开课程，《科技英语》《英语语言学》《刑法学》	3	门校级精品课程；获省级教学成果一等奖	1	项、二等奖	2	项，校级教学成果特等奖	6	项、一等奖	5	项；承担国家级、省级重点教学改革项目	3	项。	“	面向国际视野的理工科大学生	‘	英语双能力	+	文化素养	’	人才培养模式创新实验区	”	被确定为省级人才培养模式创新实验区。</p><p class=\"ql-align-justify\">		学院注重青年教师培养，提升教师教学水平。鼓励青年教师积极参加国家级、省级讲课比赛，成果显著，位居在陕高校前列。先后荣获全国高校教师教学创新大赛二等奖、全国教学创新大赛	—	中国外语微课大赛全国总决赛一等奖、外研社	“	教学之星	”	大赛全国总决赛一等奖、	“	外教社杯	”	全国高校外语教学大赛二等奖、外研社	“	教学之星	”	大赛陕西省特等奖、	“	外教社杯	”	全国高校外语教学大赛陕西赛区分赛一等奖等	40	余项省级以上奖励。</p><p class=\"ql-align-center\">		<strong>科研成果</strong></p><p class=\"ql-align-justify\">		近五年，申报获批国家社科基金项目	3	项，教育部人文社科基金项目	5	项，陕西省社会科学基金、陕西省社科界重大理论与现实问题、陕西省社科联外语专项课题等研究项目	31	项，陕西省教育厅人文社会科学专项和西安市社会科学规划基金项目	21	项，校级项目	57	项。出版专著	∕	译著、教材	29	部。发表学术论文	140	余篇。获陕西省哲学社会科学成果奖二等奖	3	项，陕西高等学校人文社会科学研究优秀成果奖二等奖、三等奖	5	项，西安市哲学社会科学优秀成果奖	3	项，陕西高校大学外语研究会年会论文一等奖	1	项。</p><p class=\"ql-align-center\">		<strong>学术交流</strong></p><p class=\"ql-align-justify\">		学院十分重视高水平学术交流活动，先后举办和承办了	“	西部地区首届翻译理论及外语教学研讨会	”“	中国科技法学会年会	”“	第十一届全国典籍翻译学术研讨会	”	等高水平学	术	会议	；	设立了	“	外国语言文学博士讲坛	”“	人文论坛	”	，定期聘请国内外知名教授、学者来学院讲学。</p><p class=\"ql-align-center\">		<strong>国际合作</strong></p><p class=\"ql-align-justify\">		学院与美国东新墨西哥大学、美国密苏里大学堪萨斯分校、日本早稻田大学、日本福井大学、日本上智大学等国外知名大学建立了良好的交流与合作关系，为师生访学、课程学习、暑期实习搭建了平台。学院教师前往英国、美国、澳大利亚、瑞士、	日本等国家知名高校深造或进修	100	余	人次；学生参加海外实习或进修项目	50	余	人次。</p><p class=\"ql-align-center\">		<strong>教学设施</strong></p><p class=\"ql-align-justify\">		学院	拥	有良好的办学条件。建有同声传译室、云网络语言实验室、	CAT	机辅翻译实验室、智慧教室、研讨室、自主学习教室、外语在线测试平台、普通话机考实验室、模拟法庭、法律实务综合模拟平台等，为人才培养提供了良好的硬件环境。</p><p class=\"ql-align-center\">		<strong>人才培养</strong></p><p class=\"ql-align-justify\">		学院以	“	提升学生综合素质、全面服务学生成才	”	为目标，坚持	“	以本为本、德育为先、能力为重、注重成长	”	，形成了以	“	文曲星领航计划	”	为引领的	“	一系一精品	”	全员育人模式，不断提升	“	一节一会一月一讲坛	”	校内知名学生品牌活动。学院	多次	承办全国大学生英语竞赛，	“	外研社杯	”	全国英语演讲、阅读、写作、辩论赛，西北地区研究生英语演讲大赛等赛事，参与人数、获奖人数屡创新高，曾获全国优秀组织奖。学院定期举办	“	英语辩论大赛	”“	英语配音大赛	”“	英语戏剧大赛	”“	日语演讲大赛	”“	法律宣传月	”	等活动，为学生成长成才搭建良好发展平台。</p><p class=\"ql-align-justify\">		学院重视学生德智体	美劳	全面发展，注重学生创新能力的培养和综合素质的提高，将理想信念教育、爱国荣校教育、成长成才教育、诚信感恩教育、形势与政策教育、安全和心理健康教育与大学生思想政治教育、校园文化活动相结合，先后涌现出全国三好学生	，	陕西省三好学生、优秀学生党员	，	全国先进班集体等一批先进典型。</p><p class=\"ql-align-center\">		<strong>毕业生去向</strong></p><p class=\"ql-align-justify\">		学院不断深化教育教学改革，创新人才培养模式，培养和造就了一批专业基础扎实，综合素质全面的优秀人才。学院通过研究生推免、海外留学、优研项目为国内外知名学府输送优质生源，毕业生先后被宾夕法尼亚大学、波士顿大学、爱丁堡大学、北京大学、浙江大学、	中国人民大学、	香港中文大学、北京外国语大学、	中国政法大学、	日本大阪府立大学、日本筑波大学等名校录取，考研率稳定在	30%	左右。毕业生进入政府、司法机关、科研院所、企事业单位等领域，就业于司法仲裁、法律服务、外事、经贸、文化、新闻出版、教育、旅游等多种行业，就业率保持在	95%	左右。</p>', '2025-11-07 12:25:02');
INSERT INTO `xueyuanbumen` VALUES (14, '009', '计算机科学与工程学院', '曲江/金花校区', '<p>	计算机科学与工程学院起步于上世纪七十年代末，1994年成立计算机系，2002年7月成立学院。</p><p>	学院下设计算机科学与技术系、网络工程系、软件工程系和物联网工程系四个教学单位，设有计算机科学与技术、网络工程、软件工程、物联网工程及人工智能五个本科专业。其中，计算机科学与技术专业2010年入选陕西省特色专业，2013年入选教育部“卓越工程师人才培养计划”，并与软件工程专业先后获批国家级一流本科专业建设点，网络工程与物联网工程专业获批“陕西省一流专业”。计算机科学与技术、网络工程和软件工程三个专业通过中国工程教育认证。</p><p>	学院具有计算机科学与技术一级博士学位授予权，软件工程一级硕士学位授予权和电子信息领域专业硕士学位。学科覆盖学院全部本科专业，形成了本、硕、博完整的高级技术人才培养体系。近三年，计算机科学与技术学科软科排名位列全国前30%。2022年，计算机科学学科进入ESI全球排名前1%。</p><p>	学院教师队伍结构合理，师资力量雄厚。现有教职工140人，其中教授、副教授55人，博士生导师15人，硕士生导师49人。学院特聘院士2人、国家级人才2人，入选陕西省教学名师3人、陕西省“特支计划”科技创新领军人才1人，省级创新人才特聘教授7人，陕西省中青年科技创新领军人才3人，陕西青年科技奖1人，陕西省高校青年杰出人才1人，陕西省青年科技新星2人。目前在校本科生1400余人，硕、博研究生、留学生500余人。</p><p class=\"ql-align-justify\">	<span style=\"background-color: rgb(253, 253, 253);\">学院坚持立德树人，不断推进教育教学改革。建成</span>国家级一流本科课程2门，省级一流课程、精品资源共享课程、在线课程等10门，并在爱课程、智慧树等国家级慕课平台上线课程4门。学院获批省级实验教学示范中心1个，拥有一流的教学、科研、实验环境，建设有计算机组成原理与接口技术、嵌入式系统、网络工程、软件工程、物联网等实验室，实验设备功能齐备、性能先进。近年来，学院获省级、校级教学成果奖20余项，在全国“互联网+”竞赛、“挑战杯”竞赛、ACM/ICPC竞赛、信息安全技术技能大赛、全国研究生移动终端应用设计创新大赛、世界机器人大赛等各项学科竞赛中获国家奖30余项，省级奖100余项。</p><p class=\"ql-align-justify\">	学院坚持<span style=\"background-color: rgb(253, 253, 253);\">基础研究与应用研究并举，科研实力显著增强。依托学院建有</span>陕西省网络计算与安全技术重点实验室、西安市轨道交通智能技术重点实验室、智能感知与系统安全创新引智基地、人机共融智能机器人陕西省高校工程研究中心等6个省市级重点科研平台。近年来，学院紧跟国家数字经济发展战略，在智能计算、计算机视觉、图像处理、网络安全、物联网技术等多个领域合理布局，凝练方向，获批陕西省创新团队支持计划2项、陕西省高校青年创新团队2项。近年来，获批国家重点研发项目课题近10项，国家自然科学基金74项，省部级重点项目近20项，累计科研经费突破1亿元；获省部级以上科技奖励8项；授权发明专利200余项；发表高水平论文500余篇；出版专著及教材20余部。</p><p class=\"ql-align-justify\">	学院广泛开展国内外交流与合作，影响力不断提升。学院与澳大利亚詹姆斯库克大学开展本硕博全层次合作办学，与美国密苏里大学堪萨斯分校开展“3+1+1”研究生联合培养计划。先后与美国、日本、英国、澳大利亚、新加坡等国家的著名大学和学术机构开展合作研究及学术交流，建立了良好的合作关系。自2018年起，学院已招收本硕博留学生21名。</p><p class=\"ql-align-justify\">	学院毕业生专业基础知识扎实、创新实践能力强，综合素质高，深受用人单位好评，一次就业率达95%以上。毕业生大多数就业于沿海和经济发达地区，在华为、腾讯等知名IT企业、科研院所及政府部门发挥着重要的作用。</p><p class=\"ql-align-justify\">	长期以来，学院秉承“惟实、励新、笃信、至善”的院训，坚持立德树人根本任务，努力培养德智体美劳全面发展的社会主义建设者和接班人，为实现追赶超越目标和推进“双一流”建设而努力奋斗！</p>', '2025-11-07 12:26:00');
INSERT INTO `xueyuanbumen` VALUES (15, '010', '土木建筑工程学院', '曲江/金花校区', '<p class=\"ql-align-justify\">土木建筑工程学院有着悠久的办学历史，办学根基可溯源到二十世纪30年代的西北联合大学土木系，并与50年代的西北工学院土木系、青岛工学院土木系和苏南工业专科学校建筑科有密切的渊源。在80余载的发展历程中，造就了一批优良的师资队伍，积累了丰富的办学经验，构建了高水平办学平台。</p><p class=\"ql-align-justify\">学院现有双聘院士2人，教职工153人。其中，教授31人，副教授46人，讲师58人；博士生导师33人，硕士生导师77人；全国优秀教师、全国优秀科技工作者、中科院百人计划、霍英东基金会高校青年教师奖、陕西省教学名师、陕西省百人计划等省部级以上人才28人次。在校本科生1151人，研究生838人，其中博士研究生144人，硕士研究生694人。</p><p class=\"ql-align-justify\">学院是首批“全国党建工作标杆院系”，设有院士工作室2个，拥有土木工程博士后流动站、土木工程一级学科博士学位授权点、土木水利博士专业学位授权点、力学一级学科硕士学位授权点、建筑学一级学科硕士学位授权点和工程管理（MEM）专业学位授权点；其中，土木工程一级博士学科覆盖结构工程、岩土工程、桥梁与隧道工程、市政工程、防灾减灾与防护工程、建设工程管理6个二级学科；力学一级硕士学科覆盖一般力学与力学基础、固体力学、流体力学和工程力学4个二级学科；建筑学硕士点覆盖建筑技术科学、建筑设计及其理论、城市设计及其理论3个学科方向。</p><p class=\"ql-align-justify\">学院拥有旱区水工程生态环境全国重点实验室、西部生态环境协同创新中心、陕西省黄土力学与工程重点实验室、陕西省智慧建造研究院、陕西高校新型智库生态水利与可持续发展研究中心、特殊岩土地下空间智能建造陕西省高校工程研究中心、人机共融智能机器人陕西省高校工程研究中心、陕西省研究生联合培养示范工作站，陕西省水利水电工程西安理工大学质量检测中心（水利部甲级资质）、西安理工大规划建筑设计研究院、西安理工大学水利水电土木建筑研究设计院，是陕西省岩土力学与工程学会理事长单位。</p><p class=\"ql-align-justify\">学院设有智能建造、土木工程、工程管理、工程力学、建筑学、城市地下空间工程、土木工程（国际班）7个本科专业。其中，土木工程专业是国家一流专业、陕西省特色专业，已三次通过住房和城乡建设部高等教育土木工程专业评估（认证）；工程管理专业是国家一流专业、陕西省特色专业，是陕西省第二所通过住房和城乡建设部高等教育工程管理专业评估（认证）的专业；城市地下空间工程专业是国家一流专业、教育部特设专业；工程力学专业是陕西省一流专业。学院建有陕西省土木工程实验教学示范中心、陕西省土木工程专业核心课程教学团队、陕西省工程管理专业人才培养模式创新实验区。有《结构力学》《土力学》《混凝土结构设计原理》《理论力学》4门国家级一流课程，有《结构力学》《土力学》《混凝土结构设计原理》《动力学建模与仿真》4门陕西省课程思政示范课程，有《工程测量学》《钢筋混凝土结构》《工程力学》《材料力学》等10门陕西省精品（资源共享）课程。</p><p class=\"ql-align-justify\">学院坚持教学、科研并重的办学方针，注重特色科研团队的形成和建设，努力构筑与学院发展相适应的高水平科研平台。学院科研工作紧密围绕国家经济建设，特别是服务于西部大开发、“一带一路”建设、智能建造与建筑工业化、黄河流域生态保护与高质量发展、西北乡村振兴，充分发挥科研优势，开展国家、省部级等各类纵向课题研究，并积极参与国家青藏铁路、南水北调、西气东输、三峡工程和西安地铁等国家和地区大、中型土木建筑和水利水电工程的科研、设计和生产任务。在全院教职员工的努力下，科研项目规模和层次不断发展，科研经费逐年递增。在1978年全国科学大会上，获得4项全国科学大会奖，1988年获国家科技进步奖3项，其中一等奖1项。近5年，学院获批国家级项目72项，新增科研项目800余项，科研到款2.1亿元；发表高水平学术论文900余篇，其中三大检索论文500余篇；出版专著/教材40余部，主、参编国家标准与行业规范14部；授权国家发明专利100余项；获陕西省科学技术一等奖等省部级科技奖励16项。近年来，主、承办国内高水平学术会议10余场；承担川藏铁路、引汉济渭、东庄水库、西安地铁及西部的机场、阳江抽蓄、渭河治理、幸福林带、秦岭保护等一批国家重大基础设施相关科研和生产任务，相关成果及应用情况受到中央电视台等媒体报道。学院积极开展国际合作与交流，与英国胡弗汉顿大学、爱尔兰利莫瑞克大学签署了本科联合培养协议，建立了良好的合作关系。并与澳大利亚詹姆斯库克大学合作，成立了国际工学院，招收土木工程本硕博学生。</p><p class=\"ql-align-justify\">学院长期坚持“育人为本、知行统一”的办学理念，重视基础理论教学和工程实践能力的培养，土木建筑领域的毕业生具备扎实的理论基础、较强的工程实践创新能力和优良的工作作风，学生就业渠道通畅，深受用人单位欢迎。</p>', '2025-11-07 12:26:51');
INSERT INTO `xueyuanbumen` VALUES (16, '011', '艺术与设计学院', '曲江校区', '<p>西安理工大学艺术与设计学院成立于2005年。学院下设视觉传达、工业设计、环境设计、影像动画4个系和1个实验中心、1个公共艺术教育中心。本科招收视觉传达设计、工业设计、摄影、艺术与科技、动画、雕塑、产品设计7个专业。学院现有专业教师90人，其中教授6人，副教授30人。教师中具有博士学位27人，在读博士4人，具有硕士学位67人。2013年学院教学团队获批陕西省省级教学团队。</p><p>学院实验中心2017年获批省级实验教学示范中心，建有计算机教学中心、艺术展厅、建筑与环艺模型实验室、CMF木工加工实验室、快速成型实验室、数字摄影实验室、数字化图形处理实验室等专业实验室等。2014年学院获批陕西省省级人才培养创新示范区，学院是“中国工业设计技术服务联盟副理事长单位”、“陕西省社会科学普及基地”、 “陕西省动漫教育基地”、“教育部包装教学分指导委员会单位”，“陕西省高校摄影学会摄影专业委员会主任单位”、“中国文化管理协会理事单位”等。</p><p><strong>人才培养方面：</strong></p><p>学院现有在校本科生1200余人。现有工业设计二级博士授予权，工业设计二级硕士授予权，设计学一级硕士授予权，机械专业学位授予权，艺术设计（MFA）专业学位授予权，形成“一体两翼”的学科体系。2020年工业设计专业获批国家级“一流专业”建设点，产品设计专业获批陕西省“一流专业”建设点。学生在全国大学生艺术展演、全国大学生广告艺术设计大赛、平遥国际摄影节、全国三维数字化创新设计大赛、全国环艺学年奖及陕西省大学生“挑战杯”竞赛、陕西省大学生各类大赛中多次获得大奖。学生整体素质全面，动手能力强，具有较强的创意设计能力，受到了用人单位的欢迎与好评，近年来本科生就业率稳定在85%以上。</p><p><strong>学术研究方面：</strong></p><p>承担国家社会科学基金项目重点项目、一般项目、青年项目；某重点项目、国家艺术基金、教育部人文社科基金、文化部研究基金等纵向课题40余项。同时还承担了为经济建设服务的设计项目百余项。学院现为“陕西省动漫教育基地”、“大学生创新教育实践中心艺术设计基地”等。教师编写出版专著、教材近30部。学院获得陕西省2011年、2017年高等教育教学成果奖一等奖。教师国画作品曾获全国第十届美展铜奖；教师摄影作品曾获“索尼世界摄影奖”二等奖；教师和学生的设计作品相继获得2015、2017、 2018德国红点（Red Dot）概念设计奖。教师设计作品曾获第十八届中国科协年会创新创业大赛铜奖；教师指导的设计作品获得“互联网+”大赛全国铜奖、陕西省银奖等；指导的摄影作品获得教育部指导教师一等奖两项。</p>', '2025-11-07 12:28:34');
INSERT INTO `xueyuanbumen` VALUES (17, '012', '马克思主义学院', '曲江校区', '<p class=\"ql-align-justify\">	西安理工大学马克思主义学院前身为北京机械学院马列教研部（1958年），2009年独立设置思想政治理论课教学科研部，2015年更名为马克思主义学院。学院为陕西省首批重点马克思主义学院、陕西省委教育工委重点扶持马克思主义学院。现设有习近平新时代中国特色社会主义思想概论教研室、马克思主义基本原理教研室、当代中国马克思主义教研室、中国近现代史纲要教研室、德育教研室、形势与政策教研室，有5个省级研究基地（中心）、1个省级人才培养模式创新实验区。</p><p class=\"ql-align-justify\">	<strong>师资队伍。</strong>现有全国优秀教师1人；教育部择优资助计划1人；全国高校思想政治理论课年度影响力提名人物3人；陕西省哲学社会科学和文化艺术领域领军人才1人；陕西省教书育人楷模1人、陕西省“巾帼标兵”1人；三秦人才津贴3人；陕西省思想政治理论课优秀教师1人；陕西高校人文社会科学青年英才支持计划1人；陕西高校青年杰出人才支持计划1人；陕西省决策咨询委员会委员1人。</p><p class=\"ql-align-justify\">	<strong>学科建设。</strong>学院2001年获批马克思主义理论与思想政治教育硕士学位授予权，2006年获批马克思主义理论一级学科硕士学位和思想政治教育二级学科博士学位授予权，2018年获批马克思主义理论一级学科博士学位授予权，2023年获批马克思主义理论学科博士后科研流动站。</p><p class=\"ql-align-justify\">	<strong>教育教学。</strong>学院承担全校本硕博学生的思想政治理论课教学工作。目前学院已建设有2门国家级一流本科课程、3门省级一流本科课程、3门省级“三进”精品课程、2门校级在线精品课程，获得省教学成果奖一、二等奖5项、省级教改重点攻关项目1项、省级思政课名师工作室1个、省级教学团队2个。在全国高校思想政治理论课教学展示活动中，共有1人获特等奖、2人获一等奖、3人次获二等奖；在陕西省思政课教师“大练兵”省级现场展示活动中，1人荣获特等奖、16人获“思政课程教学标兵”称号、6人获“思政课程教学能手”、2组师生团队获“思政课程教学团队教学能手”。</p><p class=\"ql-align-justify\">	<strong>科学研究。</strong>经过60余年的发展，学院形成了较为鲜明的研究特色和优势，围绕马克思主义基本原理与当代社会发展研究、新时代中国特色社会主义理论与实践研究、网络思想政治教育研究、中国共产党领导文化教育工作的历史进程和基本经验研究、高校思想政治理论课改革创新研究等5个学科方向展开研究。近年来，本学科共获批24项国家基金、90余项省部级课题，目前在研12项国家级项目、22项省部级科研项目，还有大量厅局级科研课题。在人民出版社、中国社会科学出版社、科学出版社等国家级出版社出版专著40余部。在《毛泽东邓小平理论研究》《思想理论教育导刊》《党的文献》《光明日报》《人民日报》等报刊发表论文800余篇。获陕西省哲学社会科学优秀成果一、二等奖7项，其他陕西省、西安市哲学社会科学优秀成果奖21项，厅局级奖项65项。</p><p class=\"ql-align-justify\">	<strong>人才培养。</strong>学院始终坚持立德树人宗旨，牢记为党育人为国育才使命，培养具有坚定马克思主义信仰，能够运用马克思主义立场、观点和方法，研究、分析与解决重大理论与现实问题的教学科研，及党政企事业单位高级研究与管理人才。</p><p class=\"ql-align-justify\">	<strong>学术交流。</strong>学院重视对外交流，先后成功举办了全国马克思主义理论博导论坛、“第二届信息化时代马克思主义理论创新与传播学术研讨会”等国际国内学术会议，与中国社科院、清华大学、美国波士顿大学、日本丽泽大学等国内外知名高校、科研院所开展广泛交流；思政课教学改革成效显著，实践育人成果获陕西省教学成果一、二等奖，教育部网站、中国教育电视台、《光明日报》《新华网》等多家媒体宣传报道，受到社会各界广泛关注。</p>', '2025-11-07 12:29:29');
INSERT INTO `xueyuanbumen` VALUES (18, '013', '电气工程学院', '曲江校区', '<p>		西安理工大学电气工程学院成立于	2019年	10月，以西安理工大学自动化学院原电气工程系和水利水电学院原电力工程系为基础组建。西安理工大学电气工程学院的前身可以追溯到	1958年北京机械学院自动控制系下设的工业企业电气化与自动化专业和	1960年陕西工业大学电机工程系下设的电厂电力网及电力系统、电机与电器专业。	1972年，北京机械学院和陕西工业大学合并组建陕西机械学院，形成了电力电子与电力传动和电力系统及其自动化两个主要分支发展方向。电力电子与电力传动方向是在原陕西机械学院自动控制系应用电子技术教研室基础上发展而来，后更名为西安理工大学自动化与信息工程学院电气工程系，主要教学科研方向为电力电子与电力传动。电力系统及其自动化方向是在原陕西机械学院水利工程系水电站动力设备教研室基础上发展而来，后发展为西安理工大学水利水电工程学院电力工程系，主要教学科研方向为电力系统及其自动化。	1998年，国家专业目录调整，两个专业统一调整为电气工程及其自动化专业，形成了一个专业由两个学院合办的格局。	2009年，电气工程及其自动化专业获批国家级特色专业称号。	2013年电气工程系新增电气类智能电网信息工程专业。	2023年学院新增储能科学与工程专业。电气工程学科的硕士生招生始于	1982年，	1984年获批电力电子与电力传动二级硕士学位授予权，	1993年电气工程学科取得电力电子与电力传动二级博士学位授予权，	1999年成为陕西省重点建设的优势学科，	2000年获批电气工程博士后流动站，	2003年获批电力系统及其自动化二级硕士学位授予权，	2011年获批电气工程一级硕士学位授予权，	2018年获批电气工程一级博士学位授予权。在全国第四轮学科水平评估中评为	C+，在第五轮学科评估中更进一步。</p><p>		历经	60余年的奋进努力，学院秉承学校优良的办学传统，践行“艰苦奋斗、自强不息”的办学精神。学院设有电力工程系、电力电子与电机系、电网信息与控制工程系、高电压与绝缘技术研究所、储能科学与工程研究所等	5个教学、科研系所和	1个电气工程实验中心，拥有专业实验室	26个，并建设有	1个校企共建国家级重点实验室，	1个校企共建国家地方联合工程实验室、	4个省级重点实验室和教学示范中心、	2个西安市重点实验室、	4个产学研基地。学院现有教职工	110人，其中教授	19人，副教授及高级工程师	28人，有国家及省部级高层次人才	5人，外籍客座教授	3名，外籍讲座教授与名誉教授	3名。目前全院在校学生	2000余人，其中本科生	1500余人，硕士、博士研究生近	500人。</p><p>		学院设有电气工程及其自动化、智能电网信息工程、储能科学与工程	3个本科专业。其中，电气工程及其自动化专业为国家级特色专业、首批国家级一流本科专业建设点。智能电网信息工程为国家首批开办的电气类本科专业。电气工程获国家卓越工程师教育培养计划	(本、硕、博）；电气工程核心课程教学团队为陕西省级教学团队。</p><p>		学院立足西北、面向全国开展电气工程领域的科学研究，特别在电力电子与特种电源装备、分布式发电与智慧能源、电力系统运行与控制、轨道交通电气控制等方面的研究取得了丰硕成果。学院教师主持纵向课题	320余项和企业委托课题	410余项，包括国家自然科学基金	48项、省部级基金	67项、国际合作项目	3项；近年来，科研课题到款	6200余万元，其中纵向课题经费	2151万元、企业委托课题经费合同额	4053万元；获得省部级及以上奖励	20项、厅局级及以上奖励	52项；发表高水平学术论文	1430余篇，其中	SCI检索	157篇、	EI检索	500余篇，在中科院一二区期刊发表论文	70余篇；出版电气工程领域中英文专著、教材	16本；授权国家发明专利	261件，其中	31项成果已得到转化。</p><p>		学院广泛开展国内外学术交流与合作，与德国、法国、日本、新加坡、美国、加拿大、澳大利亚等国的高校或科研机构签署了合作交流协定或开展学术交流，互派学者，建立了良好的合作关系。近	3年，派遣教师参加国际学术会议接近	200人次，资助学生参加国际学术会议近	30人次。各类社会团体及企业在学院设立各类奖助学金	10余项。</p><p>		学院秉持“育人为本、知行统一”的办学理念，继承传统，开拓创新，努力构建一流教学科研平台，培养理论基础扎实、创新能力强、综合素质高的电气工程领域“宽口径”、“复合型”一流工程技术人才。已为国家培养了六千余名高等专业技术人才，学院毕业生深受用人单位的好评。</p>', '2025-11-07 12:30:06');
INSERT INTO `xueyuanbumen` VALUES (19, '014', '国际工学院', '曲江校区', '<p class=\"ql-align-justify\">西安理工大学国际工学院是2020年4月经教育部批准设立，由西安理工大学和澳大利亚詹姆斯库克大学共建的非独立法人中外合作办学机构，是我国中西部地区最早拥有本科、硕士、博士多层次招生培养的中外合作办学机构，目前在校本、硕、博学生共计1090人。</p><p class=\"ql-align-justify\">合作高校詹姆斯库克大学(James Cook University，简称JCU)是澳大利亚顶尖的国立研究型大学之一，是昆士兰州建校历史第二长的大学，也是英联邦高校协会(Association of Commonwealth Universities)的会员。JCU在机械学、土木工程、电子系统与物联网、电子电气工程、大数据科学等领域具有先进教育教学和科研水平。</p><p class=\"ql-align-justify\">国际工学院是西安理工大学13个本科学院之一，本科阶段开设机械设计制造及其自动化、土木工程、电子科学与技术、计算机科学与技术4个专业，每年计划招生280人，学制4年。硕士研究生开设有机械和土木水利两个专业。</p><p class=\"ql-align-justify\">学院师资队伍由詹姆斯库克大学外籍专家教师、西安理工大学具有丰富双语教学经验的名师以及全球招聘的一流国际化师资构成，其中詹姆斯库克大学选派的外籍教师不少于30%，其讲授的核心课程门数和学时数占全部课程门数和学时数的三分之一以上。中方主要任课教师均有留学、访学经历，有多位省级教学名师、省级一流课程负责人担任核心课程主讲教师。</p><p class=\"ql-align-justify\">西安理工大学国际工学院依托两校一流专业、强势学科以及优势教育资源，以“厚德、强基、创新、融合”为人才培养理念，通过专业交叉和学科融合，面向国家战略需求和产业发展趋势，围绕“智能制造”和“智能建造”培养方向，对接新一轮科技革命与产业变革，以推动“新工科”和“双一流”背景下学校教学改革和学科建设，培养面向智能制造和智能建造及可持续发展需要，适应未来科技进步，具有国际视野、创新精神、社会担当与职业道德的精英人才和社会栋梁。</p><p class=\"ql-align-justify\">学院创新实践成果丰硕。建院以来，学生参与各类科技创新实践活动共有1200余人次，获“挑战杯”等国家级奖项74项、省级奖项119项，获奖达976人次，获奖占比高达53.43%。“互联网+”大赛获奖144项，大学生创新创业训练计划项目立项57项； 在2025年的美国大学生数学建模大赛这一国际赛事中我院一位同学获得顶级奖项（O奖）一项，并获得H奖三项，同时2025年四支队伍在2025年陕西省“挑战杯”中再创佳绩，荣膺特等奖3项、一等奖1项，同样刷新并保持我校省赛最佳战绩。</p>', '2025-11-07 12:30:42');
INSERT INTO `xueyuanbumen` VALUES (20, '015', '高科学院', '泾河/长安校区', '<p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">西安理工大学高科学院是国家教育部批准的全日制普通本科院校，是学士学位授予权单位。学院现位于陕西省西安市西咸新区泾河新城，占地面积</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">540</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">亩，建筑面积近</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">20</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">万平方米，校园环境优美，设施设备齐全，实验实训条件在同类学校中领先。大型图书中心、体育场、教学楼、现代化的实验实训室集群、信息化公寓，结合现代科技新发展，产、学、研一体的现代化校园正引领学院向国际化大学标准迈进。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院传承西安理工大学优势专业和特色专业，开设了机械设计制造及其自动化、电气工程及其自动化、水利水电工程、土木工程、包装工程、电子信息工程、计算机科学与技术、工程管理、财务管理、英语、软件工程、智能制造工程等</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">11</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">个本科专业，面向全国招生，毕业生按国家规定颁发本科毕业证书和授予学士学位。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院秉承西安理工大学的教学理念和教学管理模式进行教育教学，对传统的培养模式进行了改革和创新，加大了实践环节，大幅度提高多媒体等现代化教学手段的使用，严格教育教学督导环节，有力地保障了教学质量。学院积极探索并努力实践复合型、应用型、创新型高素质的人才培养模式和“卓越工程师”人才培养方法，培养综合素质全面发展的具有很强的竞争能力和对岗位的适应能力的应用型高级人才，毕业生就业综合竞争力得到用人单位一致好评。每年参加全国硕士研究生入学考试上线人数达到在校生的13%</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">，达到参加考研人数的51%</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院秉承了西安理工大学多年的文化积淀，共享西安理工大学优质教学资源，一大批西安理工大学著名博士生导师、教授、博士担任各学科和专业的建设负责人，一线教学高级以上职称教师占</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">70%</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">以上。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院目前设有国家奖学金、国家励志奖学金、国家助学金、学校五项年度奖以及社会企事业单位在我校设立的“万信励志奖学金”、“理工晶科励志奖学金”等多种奖、助学金，为品学兼优和家庭困难的学生提供各种奖励、资助和勤工俭学岗位。学院现有</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">20</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">多个院级学生社团，学生活动丰富多彩，完整大学生活促进了学生全面发展。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院高度重视就业工作，与当地农业银行、苏州工业园区、长三角多个经济开发区的数十家企业签署校企就业合作单位，进行实习就业基地建设合作，为我院学生就业开辟了广阔的新途径，学院毕业生就业优势明显。</span></p><p><span class=\"ql-cursor\">﻿</span>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">学院以全面提高质量为核心，着力加强内涵建设，办学水平和社会声誉稳步提升。学院正在为实现建设以工为主、多学科协调发展、特色鲜明的大学的目标而努力奋斗，努力建设成为全国独立本科院校中具有示范性、推广性、辐射性的高校。</span></p>', '2025-11-07 12:33:54');
INSERT INTO `xueyuanbumen` VALUES (21, '016', '继续教育学院', '曲江校区', '<p>	西安理工大学继续教育学院全面负责学校成人高等学历教育、非学历教育、技能培训及相关行政管理工作，是经原机械工业部批准举办成人高等学历教育的正规机构，始办于1958年，是承担成人高等继续教育较早的院校之一。1980年学校恢复夜大学招生，1981年开始招收干部专修科，1986年举办函授教育，1988年经原机械电子部批准成立成人教育学院；2002年更名为继续教育学院。</p><p>	成人学历教育的办学形式有业余、函授教育两大类。办学层次有高中起点本科、专科起点本科等，我校成人高等继续教育共有46个专业，以机械、电气、水利水电、财会、管理、印刷等为鲜明特色。</p><p>	学校为适应在职人员继续学习的需要，以更新知识和提高技能为重点，积极推进“在线学习+线下面授”的混合式教学模式改革；按照人才市场的要求，建立多形式、多层次人才培训机制和模式，在学历教育基础上，积极开展高中及大学后的非学历继续教育和各种资格证书培训。</p>', '2025-11-07 12:34:59');

-- ----------------------------
-- Table structure for yonghu
-- ----------------------------
DROP TABLE IF EXISTS `yonghu`;
CREATE TABLE `yonghu`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `username` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '账户',
  `password` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '密码',
  `xueyuanbumen_id` int NULL DEFAULT NULL COMMENT '学院部门',
  `yonghu_uuid_number` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '科研人员编号 Search111 ',
  `yonghu_name` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '科研人员姓名 Search111 ',
  `yonghu_phone` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '科研人员手机号',
  `yonghu_id_number` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '科研人员身份证号',
  `yonghu_photo` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '科研人员头像',
  `sex_types` int NULL DEFAULT NULL COMMENT '性别',
  `age` int NULL DEFAULT NULL COMMENT '年龄',
  `yonghu_email` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '电子邮箱',
  `zhiwu_types` int NULL DEFAULT NULL COMMENT '职务 Search111 ',
  `zhicheng_types` int NULL DEFAULT NULL COMMENT '职称 Search111 ',
  `xueli_types` int NULL DEFAULT NULL COMMENT '学历 Search111 ',
  `create_time` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '科研人员' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of yonghu
-- ----------------------------

SET FOREIGN_KEY_CHECKS = 1;
